var QUESTIONS_THEORY_4 = [
{type:"mcq",diff:"easy",en:{q:"What is the process of starting or restarting a computer called?",opts:["Formatting","Booting","Compiling","Execution"],ans:1,exp:"Booting is the initial set of operations that a computer performs when power is switched on. It loads the operating system into the computer's main memory (RAM). This process is essential because the hardware cannot function without the OS controlling it."},hi:{q:"कंप्यूटर को शुरू या रीस्टार्ट करने की प्रक्रिया को क्या कहा जाता है?",opts:["फॉर्मेटिंग (Formatting)","बूटिंग (Booting)","कम्पाइलिंग (Compiling)","एग्जीक्यूशन (Execution)"],ans:1,exp:"बूटिंग वह प्रारंभिक प्रक्रिया है जो कंप्यूटर को चालू करने पर निष्पादित होती है। यह ऑपरेटिंग सिस्टम को कंप्यूटर की मुख्य मेमोरी (RAM) में लोड करती है। यह प्रक्रिया आवश्यक है क्योंकि हार्डवेयर OS के नियंत्रण के बिना कार्य नहीं कर सकता।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following refers to turning on a computer that has been powered off completely?",opts:["Warm Boot","Safe Boot","Cold Boot","Soft Boot"],ans:2,exp:"A Cold Boot, also known as a hard boot, occurs when electrical power is turned on from a completely dead state. The system performs a complete Power-On Self-Test (POST) to check all hardware components before loading the OS."},hi:{q:"पूरी तरह से बंद पड़े कंप्यूटर को चालू करने को निम्नलिखित में से क्या कहा जाता है?",opts:["वार्म बूट (Warm Boot)","सेफ बूट (Safe Boot)","कोल्ड बूट (Cold Boot)","सॉफ्ट बूट (Soft Boot)"],ans:2,exp:"कोल्ड बूट (या हार्ड बूट) तब होता है जब सिस्टम को पूरी तरह से बंद अवस्था से बिजली दी जाती है। ओएस (OS) लोड करने से पहले सिस्टम सभी हार्डवेयर घटकों की जांच के लिए एक पूर्ण पावर-ऑन सेल्फ-टेस्ट (POST) करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Restarting a computer without turning off the power is known as?",opts:["Cold Boot","Hard Boot","Warm Boot","Initial Boot"],ans:2,exp:"A Warm Boot, or soft boot, refers to restarting a system already powered on without cutting the power supply. It bypasses the initial hardware tests (POST), making the booting process faster than a cold boot."},hi:{q:"बिजली बंद किए बिना कंप्यूटर को फिर से चालू करने (Restart) को क्या कहा जाता है?",opts:["कोल्ड बूट (Cold Boot)","हार्ड बूट (Hard Boot)","वार्म बूट (Warm Boot)","इनिशियल बूट (Initial Boot)"],ans:2,exp:"वार्म बूट, या सॉफ्ट बूट, बिजली की आपूर्ति काटे बिना पहले से चालू सिस्टम को पुनरारंभ करने को कहते हैं। यह प्रारंभिक हार्डवेयर परीक्षण (POST) को छोड़ देता है, जिससे बूटिंग प्रक्रिया कोल्ड बूट की तुलना में तेज हो जाती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which keyboard shortcut is traditionally used in Windows for a Warm Boot?",opts:["Ctrl + Shift + Esc","Ctrl + Alt + Del","Alt + F4","Windows + L"],ans:1,exp:"The combination of Ctrl + Alt + Del was designed originally by IBM as a soft reboot command. In modern Windows operating systems, it opens a security screen that allows users to safely restart the system or access the Task Manager."},hi:{q:"विंडोज़ में वार्म बूट के लिए पारंपरिक रूप से किस कीबोर्ड शॉर्टकट का उपयोग किया जाता है?",opts:["Ctrl + Shift + Esc","Ctrl + Alt + Del","Alt + F4","Windows + L"],ans:1,exp:"Ctrl + Alt + Del संयोजन को मूल रूप से IBM द्वारा सॉफ्ट रीबूट कमांड के रूप में डिज़ाइन किया गया था। आधुनिक विंडोज़ में, यह एक सुरक्षा स्क्रीन खोलता है जो उपयोगकर्ताओं को सिस्टम को सुरक्षित रूप से पुनरारंभ करने या टास्क मैनेजर तक पहुंचने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does BIOS stand for?",opts:["Basic Input Output System","Basic Internal Output System","Binary Input Output System","Basic Integrated Operating System"],ans:0,exp:"BIOS stands for Basic Input/Output System. It is firmware stored on a ROM chip on the motherboard that initializes hardware during the booting process and provides runtime services for operating systems."},hi:{q:"BIOS का पूर्ण रूप क्या है?",opts:["बेसिक इनपुट आउटपुट सिस्टम","बेसिक इंटरनल आउटपुट सिस्टम","बाइनरी इनपुट आउटपुट सिस्टम","बेसिक इंटीग्रेटेड ऑपरेटिंग सिस्टम"],ans:0,exp:"BIOS का अर्थ बेसिक इनपुट/आउटपुट सिस्टम है। यह मदरबोर्ड पर ROM चिप पर संग्रहीत फर्मवेयर है जो बूटिंग प्रक्रिया के दौरान हार्डवेयर को प्रारंभ करता है और ऑपरेटिंग सिस्टम के लिए रनटाइम सेवाएं प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the first program that runs when a computer is turned on?",opts:["Operating System","Bootloader","BIOS","Antivirus"],ans:2,exp:"The BIOS is the very first piece of software to run when the computer is powered on. Its primary role is to initialize and test the system hardware components and then load the bootloader from the mass storage device."},hi:{q:"कंप्यूटर चालू होने पर सबसे पहला प्रोग्राम कौन सा चलता है?",opts:["ऑपरेटिंग सिस्टम","बूटलोडर","बायोस (BIOS)","एंटीवायरस"],ans:2,exp:"कंप्यूटर चालू होने पर चलने वाला सबसे पहला सॉफ्टवेयर BIOS होता है। इसकी प्राथमिक भूमिका सिस्टम हार्डवेयर घटकों को प्रारंभ और परीक्षण करना है और फिर मास स्टोरेज डिवाइस से बूटलोडर को लोड करना है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the main function of POST?",opts:["To load the OS","To check hardware components","To format the hard disk","To manage user accounts"],ans:1,exp:"Power-On Self-Test (POST) is a diagnostic testing sequence run by a computer's BIOS to ensure that the keyboard, RAM, disk drives, and other hardware are functioning correctly before loading the operating system."},hi:{q:"POST का मुख्य कार्य क्या है?",opts:["OS को लोड करना","हार्डवेयर घटकों की जांच करना","हार्ड डिस्क को फॉर्मेट करना","उपयोगकर्ता खातों का प्रबंधन करना"],ans:1,exp:"पावर-ऑन सेल्फ-टेस्ट (POST) कंप्यूटर के BIOS द्वारा चलाया जाने वाला एक नैदानिक परीक्षण अनुक्रम है जो यह सुनिश्चित करता है कि ऑपरेटिंग सिस्टम को लोड करने से पहले कीबोर्ड, RAM, डिस्क ड्राइव और अन्य हार्डवेयर ठीक से काम कर रहे हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Where is the BIOS program physically stored in the computer?",opts:["Hard Drive","RAM","ROM/EEPROM chip","CPU Cache"],ans:2,exp:"The BIOS firmware is stored on a non-volatile ROM, EEPROM, or flash memory chip attached to the motherboard. Being non-volatile ensures that the BIOS code is retained even when the computer's power is completely shut off."},hi:{q:"BIOS प्रोग्राम भौतिक रूप से कंप्यूटर में कहाँ संग्रहीत होता है?",opts:["हार्ड ड्राइव","RAM","ROM/EEPROM चिप","CPU कैश"],ans:2,exp:"BIOS फर्मवेयर मदरबोर्ड से जुड़े एक नॉन-वोलेटाइल ROM, EEPROM या फ्लैश मेमोरी चिप पर संग्रहीत होता है। नॉन-वोलेटाइल होने से यह सुनिश्चित होता है कि कंप्यूटर की बिजली पूरी तरह से बंद होने पर भी BIOS कोड बना रहता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does POST stand for in the context of booting?",opts:["Power-On Self-Test","Pre-Operating System Task","Power-Off System Test","Primary Output System Test"],ans:0,exp:"POST stands for Power-On Self-Test. It is the initial diagnostic protocol executed by the BIOS upon power-up to verify that essential hardware components, such as CPU, RAM, and storage controllers, are operational."},hi:{q:"बूटिंग के संदर्भ में POST का पूर्ण रूप क्या है?",opts:["पावर-ऑन सेल्फ-टेस्ट","प्री-ऑपरेटिंग सिस्टम टास्क","पावर-ऑफ सिस्टम टेस्ट","प्राइमरी आउटपुट सिस्टम टेस्ट"],ans:0,exp:"POST का पूर्ण रूप पावर-ऑन सेल्फ-टेस्ट है। यह पावर-अप पर BIOS द्वारा निष्पादित प्रारंभिक नैदानिक प्रोटोकॉल है जो यह सत्यापित करता है कि आवश्यक हार्डवेयर घटक (जैसे CPU, RAM) चालू स्थिति में हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which memory chip keeps the system time, date, and basic hardware settings intact when power is off?",opts:["RAM","CMOS","ROM","Cache"],ans:1,exp:"Complementary Metal-Oxide-Semiconductor (CMOS) is a small amount of memory on a computer motherboard that stores BIOS settings, including the system date, time, and boot priority. It is powered by a small coin-cell battery."},hi:{q:"बिजली बंद होने पर कौन सी मेमोरी चिप सिस्टम का समय, तारीख और बुनियादी हार्डवेयर सेटिंग्स को सुरक्षित रखती है?",opts:["RAM","CMOS","ROM","Cache"],ans:1,exp:"कम्प्लीमेंटरी मेटल-ऑक्साइड-सेमीकंडक्टर (CMOS) कंप्यूटर मदरबोर्ड पर एक छोटी सी मेमोरी है जो सिस्टम की तारीख, समय और बूट प्राथमिकता सहित BIOS सेटिंग्स को संग्रहीत करती है। यह एक छोटी कॉइन-सेल बैटरी द्वारा संचालित होती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which battery provides power to the CMOS chip?",opts:["AA Battery","Lithium CR2032 Coin Battery","9V Battery","Lead-Acid Battery"],ans:1,exp:"A CR2032 lithium coin battery is typically used on the motherboard to provide continuous power to the CMOS chip. This prevents the loss of system time, date, and hardware configurations when the computer is unplugged."},hi:{q:"कौन सी बैटरी CMOS चिप को शक्ति (Power) प्रदान करती है?",opts:["AA बैटरी","लिथियम CR2032 कॉइन बैटरी","9V बैटरी","लेड-एसिड बैटरी"],ans:1,exp:"CR2032 लिथियम कॉइन बैटरी का उपयोग आमतौर पर मदरबोर्ड पर CMOS चिप को निरंतर शक्ति प्रदान करने के लिए किया जाता है। जब कंप्यूटर अनप्लग होता है, तो यह सिस्टम के समय, तारीख और सेटिंग्स को खोने से बचाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What indicates a successful POST process in most standard PCs?",opts:["A long continuous beep","No display on monitor","A single short beep","System automatically shutting down"],ans:2,exp:"In most legacy PC architectures, a single short beep emitted by the motherboard's internal speaker signifies that the Power-On Self-Test (POST) has completed successfully and the system is proceeding to boot the OS."},hi:{q:"अधिकांश मानक पीसी में एक सफल POST प्रक्रिया को क्या इंगित करता है?",opts:["एक लंबी निरंतर बीप","मॉनिटर पर कोई डिस्प्ले नहीं","एक सिंगल शॉर्ट बीप","सिस्टम का अपने आप बंद हो जाना"],ans:2,exp:"अधिकांश लीगेसी पीसी आर्किटेक्चर में, मदरबोर्ड के आंतरिक स्पीकर द्वारा उत्सर्जित एक सिंगल शॉर्ट बीप (छोटी बीप) यह दर्शाता है कि POST सफलतापूर्वक पूरा हो गया है और सिस्टम OS को बूट करने के लिए आगे बढ़ रहा है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary role of a bootloader?",opts:["To scan for viruses","To load the operating system into RAM","To format the hard disk partition","To control the printer output"],ans:1,exp:"A bootloader is a specialized program responsible for loading the main operating system kernel into the computer's Random Access Memory (RAM) from a storage device, passing execution control to the OS."},hi:{q:"बूटलोडर की प्राथमिक भूमिका क्या है?",opts:["वायरस के लिए स्कैन करना","ऑपरेटिंग सिस्टम को RAM में लोड करना","हार्ड डिस्क पार्टीशन को फॉर्मेट करना","प्रिंटर आउटपुट को नियंत्रित करना"],ans:1,exp:"बूटलोडर एक विशेष प्रोग्राम है जो स्टोरेज डिवाइस से मुख्य ऑपरेटिंग सिस्टम कर्नेल (Kernel) को कंप्यूटर की रैंडम एक्सेस मेमोरी (RAM) में लोड करने और OS को निष्पादन नियंत्रण सौंपने के लिए जिम्मेदार है।"}},
{type:"mcq",diff:"easy",en:{q:"What does MBR stand for?",opts:["Master Boot Record","Main Boot Register","Memory Buffer Register","Master Boot Routine"],ans:0,exp:"MBR stands for Master Boot Record. It is a vital boot sector located at the very beginning of a partitioned mass storage device, containing the bootloader code and the logical partition table of the drive."},hi:{q:"MBR का पूर्ण रूप क्या है?",opts:["मास्टर बूट रिकॉर्ड","मेन बूट रजिस्टर","मेमोरी बफर रजिस्टर","मास्टर बूट रूटीन"],ans:0,exp:"MBR का पूर्ण रूप मास्टर बूट रिकॉर्ड है। यह एक महत्वपूर्ण बूट सेक्टर है जो विभाजित मास स्टोरेज डिवाइस की बिल्कुल शुरुआत में स्थित होता है, जिसमें बूटलोडर कोड और ड्राइव की लॉजिकल पार्टीशन टेबल होती है।"}},
{type:"mcq",diff:"easy",en:{q:"Where does the OS reside before the computer is turned on?",opts:["RAM","ROM","Secondary Storage (HDD/SSD)","Cache Memory"],ans:2,exp:"Before the computer is turned on, the Operating System is permanently stored in non-volatile secondary storage, such as a Hard Disk Drive (HDD) or Solid State Drive (SSD), waiting to be loaded into RAM during boot."},hi:{q:"कंप्यूटर चालू होने से पहले OS कहाँ रहता है?",opts:["RAM","ROM","सेकेंडरी स्टोरेज (HDD/SSD)","कैश मेमोरी (Cache)"],ans:2,exp:"कंप्यूटर चालू होने से पहले, ऑपरेटिंग सिस्टम स्थायी रूप से नॉन-वोलेटाइल सेकेंडरी स्टोरेज, जैसे हार्ड डिस्क ड्राइव (HDD) या सॉलिड स्टेट ड्राइव (SSD) में संग्रहीत होता है, जो बूट के दौरान RAM में लोड होने की प्रतीक्षा करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Into which memory is the Operating System loaded during the boot process?",opts:["ROM","EEPROM","RAM","Flash Memory"],ans:2,exp:"During the booting sequence, the bootloader extracts the operating system's core files (kernel) from the hard drive and loads them into the Random Access Memory (RAM), allowing the CPU to execute OS instructions rapidly."},hi:{q:"बूट प्रक्रिया के दौरान ऑपरेटिंग सिस्टम को किस मेमोरी में लोड किया जाता है?",opts:["ROM","EEPROM","RAM","फ्लैश मेमोरी"],ans:2,exp:"बूटिंग अनुक्रम के दौरान, बूटलोडर हार्ड ड्राइव से ऑपरेटिंग सिस्टम की कोर फाइलों (कर्नेल) को निकालता है और उन्हें रैंडम एक्सेस मेमोरी (RAM) में लोड करता है, जिससे CPU को OS निर्देशों को तेजी से निष्पादित करने की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an updated, modern replacement for the traditional BIOS?",opts:["CMOS","MBR","UEFI","POST"],ans:2,exp:"Unified Extensible Firmware Interface (UEFI) is the modern specification that replaces the legacy Basic Input/Output System (BIOS). It offers faster boot times, supports larger hard drives, and includes security features like Secure Boot."},hi:{q:"निम्नलिखित में से कौन पारंपरिक BIOS का एक अद्यतन (Updated), आधुनिक प्रतिस्थापन है?",opts:["CMOS","MBR","UEFI","POST"],ans:2,exp:"यूनिफाइड एक्सटेंसिबल फर्मवेयर इंटरफेस (UEFI) वह आधुनिक विशिष्टता (specification) है जो पुराने BIOS को बदल देती है। यह तेज़ बूट समय प्रदान करता है, बड़े हार्ड ड्राइव का समर्थन करता है, और इसमें सिक्योर बूट जैसी सुरक्षा सुविधाएँ शामिल हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does UEFI stand for?",opts:["Unified Extensible Firmware Interface","Universal External Firmware Interface","Unified Extra Flash Interface","Universal Extensible Firmware Interface"],ans:0,exp:"UEFI stands for Unified Extensible Firmware Interface. It serves as a software interface between an operating system and platform firmware, replacing the older IBM PC BIOS architecture with a much more flexible environment."},hi:{q:"UEFI का पूर्ण रूप क्या है?",opts:["यूनिफाइड एक्सटेंसिबल फर्मवेयर इंटरफेस","यूनिवर्सल एक्सटर्नल फर्मवेयर इंटरफेस","यूनिफाइड एक्स्ट्रा फ्लैश इंटरफेस","यूनिवर्सल एक्सटेंसिबल फर्मवेयर इंटरफेस"],ans:0,exp:"UEFI का पूर्ण रूप यूनिफाइड एक्सटेंसिबल फर्मवेयर इंटरफेस है। यह एक ऑपरेटिंग सिस्टम और प्लेटफ़ॉर्म फ़र्मवेयर के बीच सॉफ़्टवेयर इंटरफ़ेस के रूप में कार्य करता है, जो पुराने IBM PC BIOS आर्किटेक्चर को बहुत अधिक लचीले वातावरण से बदल देता है।"}},
{type:"mcq",diff:"easy",en:{q:"The process of arranging devices in the sequence the BIOS should check for a bootloader is called:",opts:["Boot Priority / Boot Sequence","POST order","Boot Sectoring","Disk formatting"],ans:0,exp:"Boot Priority (or Boot Sequence) is a setting in the BIOS/UEFI that dictates the order of storage devices (like USB, CD-ROM, HDD) the system will attempt to read from to find a valid bootable operating system."},hi:{q:"उस प्रक्रिया को क्या कहा जाता है जिसमें BIOS को बूटलोडर के लिए उपकरणों की जांच करने का क्रम व्यवस्थित किया जाता है?",opts:["बूट प्राथमिकता (Boot Priority) / बूट अनुक्रम","POST क्रम","बूट सेक्टरिंग","डिस्क फॉर्मेटिंग"],ans:0,exp:"बूट प्रायोरिटी (या बूट सीक्वेंस) BIOS/UEFI में एक सेटिंग है जो स्टोरेज डिवाइस (जैसे USB, CD-ROM, HDD) के उस क्रम को तय करती है, जहां से सिस्टम वैध बूटेबल ऑपरेटिंग सिस्टम खोजने का प्रयास करेगा।"}},
{type:"mcq",diff:"easy",en:{q:"Which Windows OS file acts as the primary bootloader in older versions like Windows XP?",opts:["NTOSKRNL.EXE","NTLDR","BOOTMGR","WINLOAD.EXE"],ans:1,exp:"NTLDR (NT Loader) was the primary bootloader used by the Windows NT operating system series, up to and including Windows XP and Windows Server 2003, before it was replaced by BOOTMGR in Windows Vista and later."},hi:{q:"विंडोज एक्सपी (Windows XP) जैसे पुराने संस्करणों में कौन सी विंडोज ओएस फाइल प्राथमिक बूटलोडर के रूप में कार्य करती है?",opts:["NTOSKRNL.EXE","NTLDR","BOOTMGR","WINLOAD.EXE"],ans:1,exp:"NTLDR (NT लोडर) प्राथमिक बूटलोडर था जिसका उपयोग विंडोज NT ऑपरेटिंग सिस्टम श्रृंखला द्वारा किया जाता था, जिसमें विंडोज एक्सपी और विंडोज सर्वर 2003 तक शामिल थे, इससे पहले कि इसे विंडोज विस्टा और बाद में BOOTMGR द्वारा बदल दिया गया।"}},
{type:"mcq",diff:"easy",en:{q:"Which feature allows Windows to boot with only essential drivers and services to fix problems?",opts:["Fast Boot","Safe Mode","Normal Mode","Hibernate Mode"],ans:1,exp:"Safe Mode is a diagnostic startup mode in Windows operating systems used to troubleshoot critical system issues. It loads only the absolute minimum generic drivers and services required for the OS to function."},hi:{q:"कौन सी सुविधा विंडोज़ को समस्याओं को ठीक करने के लिए केवल आवश्यक ड्राइवरों और सेवाओं के साथ बूट करने की अनुमति देती है?",opts:["फास्ट बूट","सेफ मोड (Safe Mode)","नॉर्मल मोड","हाइबरनेट मोड"],ans:1,exp:"सेफ मोड विंडोज ऑपरेटिंग सिस्टम में एक डायग्नोस्टिक स्टार्टअप मोड है जिसका उपयोग महत्वपूर्ण सिस्टम समस्याओं के निवारण के लिए किया जाता है। यह OS को कार्य करने के लिए आवश्यक केवल न्यूनतम जेनेरिक ड्राइवरों और सेवाओं को लोड करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which key is frequently pressed during boot to enter the BIOS/UEFI Setup Utility?",opts:["Spacebar","Del or F2","Shift","Ctrl + C"],ans:1,exp:"Depending on the motherboard manufacturer, pressing the 'Del' (Delete) key or 'F2' key rapidly during the early POST phase interrupts the normal boot sequence and opens the BIOS/UEFI configuration menu."},hi:{q:"BIOS/UEFI सेटअप उपयोगिता में प्रवेश करने के लिए बूट के दौरान अक्सर कौन सी कुंजी (Key) दबाई जाती है?",opts:["Spacebar","Del या F2","Shift","Ctrl + C"],ans:1,exp:"मदरबोर्ड निर्माता के आधार पर, प्रारंभिक POST चरण के दौरान 'Del' (Delete) कुंजी या 'F2' कुंजी को तेज़ी से दबाने से सामान्य बूट अनुक्रम बाधित होता है और BIOS/UEFI कॉन्फ़िगरेशन मेनू खुल जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does a 'Non-system disk or disk error' message usually mean?",opts:["The monitor is disconnected","There is no OS on the boot device","The RAM is faulty","The keyboard is unplugged"],ans:1,exp:"The 'Non-system disk' error typically occurs when the BIOS tries to boot from a storage drive (like a floppy or USB) that does not contain a valid bootloader or operating system files, halting the boot process."},hi:{q:"'Non-system disk or disk error' संदेश का आमतौर पर क्या अर्थ होता है?",opts:["मॉनिटर डिस्कनेक्ट हो गया है","बूट डिवाइस पर कोई OS नहीं है","RAM खराब है","कीबोर्ड अनप्लग है"],ans:1,exp:"'नॉन-सिस्टम डिस्क' त्रुटि आमतौर पर तब होती है जब BIOS किसी स्टोरेज ड्राइव (जैसे फ्लॉपी या USB) से बूट करने का प्रयास करता है जिसमें वैध बूटलोडर या ऑपरेटिंग सिस्टम फाइलें नहीं होती हैं, जिससे बूट प्रक्रिया रुक जाती है।"}},
{type:"mcq",diff:"easy",en:{q:"What type of software is GRUB?",opts:["Antivirus","Bootloader for Linux","Web Browser","Word Processor"],ans:1,exp:"GNU GRUB (GRand Unified Bootloader) is a very common bootloader package from the GNU Project, extensively used by Unix-like operating systems such as Linux, to provide a menu to boot one of multiple installed OS."},hi:{q:"GRUB किस प्रकार का सॉफ्टवेयर है?",opts:["एंटीवायरस","लिनक्स के लिए बूटलोडर","वेब ब्राउज़र","वर्ड प्रोसेसर"],ans:1,exp:"GNU GRUB (ग्रैंड यूनिफाइड बूटलोडर) GNU प्रोजेक्ट का एक बहुत ही सामान्य बूटलोडर पैकेज है, जिसका व्यापक रूप से लिनक्स जैसे यूनिक्स-जैसे ऑपरेटिंग सिस्टम द्वारा उपयोग किया जाता है, ताकि कई स्थापित OS में से किसी एक को बूट करने के लिए मेनू प्रदान किया जा सके।"}},
{type:"mcq",diff:"easy",en:{q:"Which key is typically used in Windows 7 to access the Advanced Boot Options (like Safe Mode)?",opts:["F1","F8","F12","F10"],ans:1,exp:"In Windows 7 and earlier versions, pressing the F8 key repeatedly just before the Windows logo appears prompts the Advanced Boot Options menu. This menu allows users to select diagnostic modes like Safe Mode."},hi:{q:"विंडोज 7 में एडवांस बूट ऑप्शंस (जैसे सेफ मोड) तक पहुंचने के लिए आमतौर पर किस कीबोर्ड की का उपयोग किया जाता है?",opts:["F1","F8","F12","F10"],ans:1,exp:"विंडोज 7 और पुराने संस्करणों में, विंडोज लोगो दिखाई देने से ठीक पहले बार-बार F8 कुंजी दबाने से उन्नत बूट विकल्प (Advanced Boot Options) मेनू आता है। यह मेनू उपयोगकर्ताओं को सेफ मोड जैसे नैदानिक ​​मोड का चयन करने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of BCD in modern Windows boot process?",opts:["Boot Configuration Data","Basic Computer Drive","Binary Code Decimal","Boot Control Directory"],ans:0,exp:"Boot Configuration Data (BCD) is a firmware-independent database used by Windows (starting from Vista) for boot-time configuration data. It completely replaces the older boot.ini text file used in Windows XP."},hi:{q:"आधुनिक विंडोज बूट प्रक्रिया में BCD का पूर्ण रूप क्या है?",opts:["बूट कॉन्फ़िगरेशन डेटा (Boot Configuration Data)","बेसिक कंप्यूटर ड्राइव","बाइनरी कोड डेसिमल","बूट कंट्रोल डायरेक्टरी"],ans:0,exp:"बूट कॉन्फ़िगरेशन डेटा (BCD) एक फर्मवेयर-स्वतंत्र डेटाबेस है जिसका उपयोग विंडोज़ (विस्टा से शुरू) द्वारा बूट-टाइम कॉन्फ़िगरेशन डेटा के लिए किया जाता है। यह विंडोज एक्सपी में उपयोग की जाने वाली पुरानी boot.ini टेक्स्ट फ़ाइल को पूरी तरह से बदल देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which component acts as the bridge between hardware and the OS?",opts:["Microsoft Word","BIOS","Monitor","SMPS"],ans:1,exp:"The BIOS serves as the essential bridge or intermediary layer between the physical hardware components of the PC and the software operating system, facilitating low-level communication and hardware initialization."},hi:{q:"कौन सा घटक हार्डवेयर और OS के बीच सेतु (bridge) के रूप में कार्य करता है?",opts:["माइक्रोसॉफ्ट वर्ड","बायोस (BIOS)","मॉनिटर","एसएमपीएस (SMPS)"],ans:1,exp:"BIOS पीसी के भौतिक हार्डवेयर घटकों और सॉफ्टवेयर ऑपरेटिंग सिस्टम के बीच आवश्यक पुल या मध्यस्थ परत के रूप में कार्य करता है, जो निम्न-स्तरीय संचार और हार्डवेयर आरंभीकरण की सुविधा प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"A continuous sequence of short beeps during POST usually indicates a problem with which component?",opts:["Motherboard or Power Supply","Mouse","Operating System","Audio card"],ans:0,exp:"A continuous sequence of short beeps generated during the POST phase generally points to a severe hardware fault, most commonly related to the Motherboard or a failing Power Supply Unit (PSU) delivering unstable voltages."},hi:{q:"POST के दौरान छोटी बीप का लगातार क्रम आमतौर पर किस घटक (component) की समस्या को इंगित करता है?",opts:["मदरबोर्ड या पावर सप्लाई","माउस","ऑपरेटिंग सिस्टम","ऑडियो कार्ड"],ans:0,exp:"POST चरण के दौरान उत्पन्न होने वाली छोटी बीप का निरंतर क्रम आम तौर पर एक गंभीर हार्डवेयर दोष की ओर इशारा करता है, जो आमतौर पर मदरबोर्ड या अस्थिर वोल्टेज प्रदान करने वाली विफल बिजली आपूर्ति इकाई (PSU) से संबंधित होता है।"}},
{type:"tf",diff:"easy",en:{q:"Cold booting takes less time than warm booting.",opts:["True","False"],ans:1,exp:"False. Cold booting takes more time than warm booting because it involves the full POST sequence and initial hardware checks from a fully powered-off state, whereas warm booting bypasses these preliminary steps."},hi:{q:"कोल्ड बूटिंग में वार्म बूटिंग की तुलना में कम समय लगता है।",opts:["सही","गलत"],ans:1,exp:"गलत। वार्म बूटिंग की तुलना में कोल्ड बूटिंग में अधिक समय लगता है क्योंकि इसमें पूरी तरह से बंद अवस्था से पूर्ण POST अनुक्रम और प्रारंभिक हार्डवेयर जाँच शामिल होती है, जबकि वार्म बूटिंग इन प्रारंभिक चरणों को छोड़ देती है।"}},
{type:"tf",diff:"easy",en:{q:"The Operating System remains in the RAM when the computer is shut down.",opts:["True","False"],ans:1,exp:"False. RAM is a volatile memory, meaning it loses all its stored data when electrical power is removed. The Operating System must be reloaded from the non-volatile hard drive back into RAM during every boot process."},hi:{q:"कंप्यूटर बंद होने पर ऑपरेटिंग सिस्टम RAM में ही रहता है।",opts:["सही","गलत"],ans:1,exp:"गलत। RAM एक अस्थिर (volatile) मेमोरी है, जिसका अर्थ है कि बिजली कटने पर इसका सारा डेटा नष्ट हो जाता है। प्रत्येक बूट प्रक्रिया के दौरान ऑपरेटिंग सिस्टम को नॉन-वोलेटाइल हार्ड ड्राइव से RAM में वापस लोड किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Which sector on a hard disk is explicitly designated as the Master Boot Record (MBR)?",opts:["Sector 0","Sector 1","Sector 100","Last Sector"],ans:0,exp:"The Master Boot Record (MBR) is always located at the very first sector of a partitioned mass storage device. In CHS (Cylinder-Head-Sector) addressing, it is logically known as Cylinder 0, Head 0, Sector 1, or simply LBA Sector 0."},hi:{q:"हार्ड डिस्क पर किस सेक्टर को विशेष रूप से मास्टर बूट रिकॉर्ड (MBR) के रूप में नामित किया गया है?",opts:["सेक्टर 0","सेक्टर 1","सेक्टर 100","अंतिम सेक्टर"],ans:0,exp:"मास्टर बूट रिकॉर्ड (MBR) हमेशा एक विभाजित मास स्टोरेज डिवाइस के सबसे पहले सेक्टर में स्थित होता है। CHS (सिलेंडर-हेड-सेक्टर) एड्रेसिंग में, इसे तार्किक रूप से सिलेंडर 0, हेड 0, सेक्टर 1 या केवल LBA सेक्टर 0 के रूप में जाना जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the maximum number of primary partitions an MBR disk can inherently support?",opts:["2","4","8","128"],ans:1,exp:"The traditional MBR partition table structure is exactly 64 bytes in size. Since each primary partition entry requires 16 bytes, the MBR can only strictly define and support up to 4 primary partitions."},hi:{q:"MBR डिस्क स्वाभाविक रूप से अधिकतम कितने प्राइमरी पार्टीशन का समर्थन कर सकती है?",opts:["2","4","8","128"],ans:1,exp:"पारंपरिक MBR पार्टीशन टेबल संरचना का आकार ठीक 64 बाइट्स होता है। चूँकि प्रत्येक प्राइमरी पार्टीशन प्रविष्टि के लिए 16 बाइट्स की आवश्यकता होती है, MBR केवल 4 प्राइमरी पार्टीशन को सख्ती से परिभाषित और समर्थन कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following bootloaders is utilized by newer Windows operating systems (Vista, 7, 10, 11)?",opts:["NTLDR","LILO","BOOTMGR","SYSLINUX"],ans:2,exp:"Windows Boot Manager (BOOTMGR) is the primary bootloader introduced by Microsoft starting from Windows Vista. It reads boot parameters from the Boot Configuration Data (BCD) store and executes winload.exe to load the kernel."},hi:{q:"नए विंडोज़ ऑपरेटिंग सिस्टम (विस्टा, 7, 10, 11) द्वारा निम्नलिखित में से किस बूटलोडर का उपयोग किया जाता है?",opts:["NTLDR","LILO","BOOTMGR","SYSLINUX"],ans:2,exp:"विंडोज़ बूट मैनेजर (BOOTMGR) माइक्रोसॉफ्ट द्वारा विंडोज़ विस्टा से शुरू किया गया प्राथमिक बूटलोडर है। यह बूट कॉन्फ़िगरेशन डेटा (BCD) स्टोर से बूट पैरामीटर पढ़ता है और कर्नेल को लोड करने के लिए winload.exe निष्पादित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What file was used in Windows XP to present an OS selection menu and define boot paths?",opts:["bootmgr","boot.ini","bcdedit.exe","config.sys"],ans:1,exp:"In older Windows NT-based systems like Windows XP, the 'boot.ini' file was a hidden system text file situated at the root directory. It provided NTLDR with the paths to OS installations and displayed the boot menu."},hi:{q:"Windows XP में OS चयन मेनू प्रस्तुत करने और बूट पथ परिभाषित करने के लिए किस फ़ाइल का उपयोग किया गया था?",opts:["bootmgr","boot.ini","bcdedit.exe","config.sys"],ans:1,exp:"विंडोज एक्सपी जैसे पुराने विंडोज एनटी-आधारित सिस्टम में, 'boot.ini' रूट डायरेक्टरी में स्थित एक छिपी हुई सिस्टम टेक्स्ट फाइल थी। इसने NTLDR को OS इंस्टॉलेशन के पथ प्रदान किए और बूट मेनू प्रदर्शित किया।"}},
{type:"mcq",diff:"medium",en:{q:"If a motherboard produces 'One long beep, two short beeps' during POST, what is the most likely issue?",opts:["Hard drive failure","Video/Graphics card error","Keyboard missing","Normal boot"],ans:1,exp:"In many traditional BIOS implementations (like IBM or AMI), one long beep followed by two short beeps is an error code explicitly denoting a failure to initialize the Video adapter or Graphics card."},hi:{q:"यदि कोई मदरबोर्ड POST के दौरान 'एक लंबी बीप, दो छोटी बीप' (One long beep, two short beeps) उत्पन्न करता है, तो सबसे संभावित समस्या क्या है?",opts:["हार्ड ड्राइव की विफलता","वीडियो/ग्राफ़िक्स कार्ड त्रुटि","कीबोर्ड गायब","सामान्य बूट"],ans:1,exp:"कई पारंपरिक BIOS कार्यान्वयनों (जैसे IBM या AMI) में, एक लंबी बीप के बाद दो छोटी बीप एक त्रुटि कोड है जो विशेष रूप से वीडियो एडाप्टर या ग्राफिक्स कार्ड को प्रारंभ करने में विफलता को दर्शाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the standard byte size of a Master Boot Record (MBR) sector?",opts:["256 bytes","512 bytes","1024 bytes","4096 bytes"],ans:1,exp:"A standard MBR sector consists of exactly 512 bytes. This includes 446 bytes for the bootstrap code area, 64 bytes for the partition table (4 entries of 16 bytes each), and a 2-byte boot signature (0x55AA)."},hi:{q:"मास्टर बूट रिकॉर्ड (MBR) सेक्टर का मानक बाइट आकार क्या है?",opts:["256 बाइट्स","512 बाइट्स","1024 बाइट्स","4096 बाइट्स"],ans:1,exp:"एक मानक MBR सेक्टर ठीक 512 बाइट्स का होता है। इसमें बूटस्ट्रैप कोड क्षेत्र के लिए 446 बाइट्स, पार्टीशन टेबल (प्रत्येक 16 बाइट्स की 4 प्रविष्टियां) के लिए 64 बाइट्स और 2-बाइट बूट हस्ताक्षर (0x55AA) शामिल हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which executable file is responsible for initializing the Windows Kernel (ntoskrnl.exe) in modern Windows OS?",opts:["boot.ini","winload.exe","smss.exe","explorer.exe"],ans:1,exp:"In the modern Windows boot process (Vista and newer), BOOTMGR invokes 'winload.exe'. Winload.exe's precise job is to load the essential device drivers and the Windows kernel (ntoskrnl.exe) into memory."},hi:{q:"आधुनिक विंडोज OS में विंडोज कर्नेल (ntoskrnl.exe) को इनिशियलाइज़ करने के लिए कौन सी निष्पादन योग्य (executable) फ़ाइल ज़िम्मेदार है?",opts:["boot.ini","winload.exe","smss.exe","explorer.exe"],ans:1,exp:"आधुनिक विंडोज़ बूट प्रक्रिया (विस्टा और नए) में, BOOTMGR 'winload.exe' को शुरू करता है। Winload.exe का सटीक काम मेमोरी में आवश्यक डिवाइस ड्राइवर और विंडोज़ कर्नेल (ntoskrnl.exe) को लोड करना है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the full form of GPT in the context of modern hard drive partitioning?",opts:["General Partition Table","GUID Partition Table","Global Partition Track","Gigabyte Partition Table"],ans:1,exp:"GPT stands for GUID Partition Table. It is the modern standard for laying out the partition table on a physical hard disk, using Globally Unique Identifiers (GUIDs). It overcomes the 2TB disk size limitation of MBR."},hi:{q:"आधुनिक हार्ड ड्राइव पार्टीशनिंग के संदर्भ में GPT का पूर्ण रूप क्या है?",opts:["जनरल पार्टीशन टेबल","GUID पार्टीशन टेबल (GUID Partition Table)","ग्लोबल पार्टीशन ट्रैक","गीगाबाइट पार्टीशन टेबल"],ans:1,exp:"GPT का अर्थ GUID पार्टीशन टेबल है। यह विश्व स्तर पर अद्वितीय पहचानकर्ता (GUIDs) का उपयोग करके भौतिक हार्ड डिस्क पर पार्टीशन टेबल तैयार करने का आधुनिक मानक है। यह MBR की 2TB डिस्क आकार सीमा को पार करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What happens if the CMOS battery dies completely?",opts:["Computer bursts into flames","Hard drive data is erased automatically","System time resets and BIOS configurations are lost","Operating System gets uninstalled"],ans:2,exp:"If the CR2032 CMOS battery depletes entirely, the volatile CMOS memory loses power. As a result, custom BIOS settings, boot sequences, and the real-time clock (RTC) reset to factory defaults upon every reboot."},hi:{q:"यदि CMOS बैटरी पूरी तरह ख़त्म हो जाए तो क्या होता है?",opts:["कंप्यूटर में आग लग जाती है","हार्ड ड्राइव का डेटा अपने आप मिट जाता है","सिस्टम का समय रीसेट हो जाता है और BIOS कॉन्फ़िगरेशन खो जाता है","ऑपरेटिंग सिस्टम अनइंस्टॉल हो जाता है"],ans:2,exp:"यदि CR2032 CMOS बैटरी पूरी तरह से खत्म हो जाती है, तो अस्थिर (volatile) CMOS मेमोरी की पावर खत्म हो जाती है। परिणामस्वरूप, कस्टम BIOS सेटिंग्स, बूट अनुक्रम और रियल-टाइम क्लॉक (RTC) हर रीबूट पर फ़ैक्टरी डिफ़ॉल्ट पर रीसेट हो जाते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which program manages the initial startup of user-mode processes in Windows and handles the creation of system environment variables?",opts:["hal.dll","smss.exe","bootmgr","ntldr"],ans:1,exp:"The Session Manager Subsystem (smss.exe) is a critical user-mode component started by the Windows kernel during boot. It initializes the environment, starts the Win32 subsystem (csrss.exe), and handles Winlogon."},hi:{q:"कौन सा प्रोग्राम विंडोज़ में उपयोगकर्ता-मोड (user-mode) प्रक्रियाओं के प्रारंभिक स्टार्टअप का प्रबंधन करता है और सिस्टम पर्यावरण चर (environment variables) के निर्माण को संभालता है?",opts:["hal.dll","smss.exe","bootmgr","ntldr"],ans:1,exp:"सत्र प्रबंधक उपप्रणाली (smss.exe) एक महत्वपूर्ण उपयोगकर्ता-मोड घटक है जो बूट के दौरान विंडोज़ कर्नेल द्वारा शुरू किया जाता है। यह पर्यावरण को इनिशियलाइज़ करता है, Win32 सबसिस्टम (csrss.exe) शुरू करता है, और Winlogon को संभालता है।"}},
{type:"mcq",diff:"medium",en:{q:"In a dual-boot scenario with Linux and Windows, which bootloader is most commonly installed to allow switching between both OS?",opts:["BOOTMGR","NTLDR","GRUB","LILO"],ans:2,exp:"When dual-booting Linux and Windows, the GNU GRUB (GRand Unified Bootloader) is typically installed in the MBR/EFI partition. It identifies the Windows bootloader natively and offers a menu to launch either Linux or Windows."},hi:{q:"लिनक्स और विंडोज़ वाले डुअल-बूट परिदृश्य में, दोनों ओएस के बीच स्विच करने के लिए आमतौर पर कौन सा बूटलोडर स्थापित किया जाता है?",opts:["BOOTMGR","NTLDR","GRUB","LILO"],ans:2,exp:"लिनक्स और विंडोज को डुअल-बूट करते समय, GNU GRUB (ग्रैंड यूनिफाइड बूटलोडर) को आम तौर पर MBR/EFI विभाजन में स्थापित किया जाता है। यह मूल रूप से विंडोज बूटलोडर की पहचान करता है और लिनक्स या विंडोज को लॉन्च करने के लिए एक मेनू प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following errors directly indicates a corrupted or missing Boot Configuration Data store?",opts:["Non-system disk","CMOS checksum error","BOOTMGR is missing","0xC0000034 / BCD error"],ans:3,exp:"An error code like 0xC0000034 specifically relates to a missing, unreadable, or corrupted BCD file. 'BOOTMGR is missing' implies the bootloader executable itself is absent, not necessarily the BCD store."},hi:{q:"निम्नलिखित में से कौन सी त्रुटि सीधे दूषित या गायब बूट कॉन्फ़िगरेशन डेटा (BCD) को इंगित करती है?",opts:["नॉन-सिस्टम डिस्क","CMOS चेकसम एरर","BOOTMGR is missing","0xC0000034 / BCD error"],ans:3,exp:"0xC0000034 जैसा त्रुटि कोड विशेष रूप से गायब, अपठनीय या दूषित BCD फ़ाइल से संबंधित है। 'BOOTMGR is missing' का अर्थ है कि बूटलोडर निष्पादन योग्य फ़ाइल ही अनुपस्थित है, ज़रूरी नहीं कि BCD स्टोर।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'Active' flag indicate on a primary partition in an MBR disk?",opts:["It is currently formatted","It is the partition containing the bootloader to be executed","It is the largest partition","It contains personal user data"],ans:1,exp:"In an MBR partitioned drive, marking a primary partition as 'Active' dictates to the Master Boot Record code that this specific partition contains the Volume Boot Record (VBR) and bootloader required to start the OS."},hi:{q:"MBR डिस्क में प्राइमरी पार्टीशन पर 'सक्रिय' (Active) फ्लैग क्या दर्शाता है?",opts:["यह वर्तमान में स्वरूपित (formatted) है","यह वह पार्टीशन है जिसमें निष्पादित किया जाने वाला बूटलोडर शामिल है","यह सबसे बड़ा पार्टीशन है","इसमें व्यक्तिगत उपयोगकर्ता डेटा है"],ans:1,exp:"MBR पार्टीशन ड्राइव में, किसी प्राइमरी पार्टीशन को 'सक्रिय' (Active) के रूप में चिह्नित करना मास्टर बूट रिकॉर्ड कोड को यह निर्देशित करता है कि इस विशिष्ट पार्टीशन में OS शुरू करने के लिए आवश्यक वॉल्यूम बूट रिकॉर्ड (VBR) और बूटलोडर शामिल है।"}},
{type:"mcq",diff:"medium",en:{q:"What command-line tool is used in modern Windows environments to edit the boot menu and settings?",opts:["bootcfg","fdisk","bcdedit","diskpart"],ans:2,exp:"BCDEdit (Boot Configuration Data Editor) is a command-line tool included in Windows (Vista and later) used specifically to view, create, edit, and modify the BCD store, altering how the system boots."},hi:{q:"बूट मेनू और सेटिंग्स को संपादित (edit) करने के लिए आधुनिक विंडोज़ वातावरण में किस कमांड-लाइन टूल का उपयोग किया जाता है?",opts:["bootcfg","fdisk","bcdedit","diskpart"],ans:2,exp:"BCDEdit (बूट कॉन्फ़िगरेशन डेटा एडिटर) विंडोज (विस्टा और बाद के) में शामिल एक कमांड-लाइन टूल है जिसका उपयोग विशेष रूप से BCD स्टोर को देखने, बनाने, संपादित करने और संशोधित करने के लिए किया जाता है, जो सिस्टम के बूट होने के तरीके को बदलता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which Linux utility initialized all other processes immediately after the Linux kernel booted historically?",opts:["systemd","bash","init","cron"],ans:2,exp:"Historically in Unix and Linux systems, 'init' was the first process executed by the kernel (assigned Process ID 1). It reads /etc/inittab and is responsible for starting all other system services. (Modern systems use systemd)."},hi:{q:"ऐतिहासिक रूप से लिनक्स कर्नेल के बूट होने के तुरंत बाद किस लिनक्स उपयोगिता ने अन्य सभी प्रक्रियाओं को प्रारंभ किया था?",opts:["systemd","bash","init","cron"],ans:2,exp:"ऐतिहासिक रूप से यूनिक्स और लिनक्स सिस्टम में, 'init' कर्नेल द्वारा निष्पादित होने वाली पहली प्रक्रिया थी (जिसे प्रोसेस आईडी 1 सौंपा गया था)। यह /etc/inittab पढ़ता है और अन्य सभी सिस्टम सेवाओं को शुरू करने के लिए जिम्मेदार है। (आधुनिक सिस्टम systemd का उपयोग करते हैं)।"}},
{type:"mcq",diff:"medium",en:{q:"What is the Power Good Signal?",opts:["A software alert from the OS","A hardware signal from the power supply confirming stable voltage","A green LED on the monitor","A BIOS beep code"],ans:1,exp:"The Power Good Signal (or Power OK) is an electrical signal sent by the computer's power supply unit to the motherboard, confirming that DC output voltages are stable and within the correct specification to begin booting."},hi:{q:"पावर गुड सिग्नल (Power Good Signal) क्या है?",opts:["OS से एक सॉफ्टवेयर अलर्ट","स्थिर वोल्टेज की पुष्टि करने वाला पावर सप्लाई से एक हार्डवेयर सिग्नल","मॉनिटर पर एक हरी LED","एक BIOS बीप कोड"],ans:1,exp:"पावर गुड सिग्नल (या पावर ओके) कंप्यूटर की बिजली आपूर्ति इकाई (PSU) द्वारा मदरबोर्ड को भेजा गया एक विद्युत संकेत है, जो इस बात की पुष्टि करता है कि डीसी आउटपुट वोल्टेज स्थिर हैं और बूटिंग शुरू करने के लिए सही विनिर्देश के भीतर हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which file encapsulates the Hardware Abstraction Layer in a Windows OS architecture?",opts:["ntoskrnl.exe","hal.dll","winload.exe","explorer.exe"],ans:1,exp:"The Hardware Abstraction Layer (HAL) is implemented in Windows via the 'hal.dll' file. It acts as an interface that hides the physical hardware differences from the OS kernel, ensuring portability across different motherboard architectures."},hi:{q:"विंडोज OS आर्किटेक्चर में कौन सी फ़ाइल हार्डवेयर एब्सट्रैक्शन लेयर (HAL) को इनकैप्सुलेट (encapsulates) करती है?",opts:["ntoskrnl.exe","hal.dll","winload.exe","explorer.exe"],ans:1,exp:"हार्डवेयर एब्सट्रैक्शन लेयर (HAL) को विंडोज़ में 'hal.dll' फ़ाइल के माध्यम से लागू किया जाता है। यह एक इंटरफ़ेस के रूप में कार्य करता है जो OS कर्नेल से भौतिक हार्डवेयर अंतर को छुपाता है, जिससे विभिन्न मदरबोर्ड आर्किटेक्चर में सुवाह्यता (portability) सुनिश्चित होती है।"}},
{type:"mcq",diff:"medium",en:{q:"During booting, what does the term VBR mean?",opts:["Volume Boot Record","Video BIOS ROM","Virtual Boot Routine","Variable Boot RAM"],ans:0,exp:"VBR stands for Volume Boot Record. While the MBR is at the start of the disk, the VBR is the first sector of a specific partition. The MBR points to the active partition's VBR to load the OS-specific bootloader."},hi:{q:"बूटिंग के दौरान, VBR शब्द का क्या अर्थ है?",opts:["वॉल्यूम बूट रिकॉर्ड (Volume Boot Record)","वीडियो BIOS ROM","वर्चुअल बूट रूटीन","वेरिएबल बूट RAM"],ans:0,exp:"VBR का पूर्ण रूप वॉल्यूम बूट रिकॉर्ड है। जबकि MBR डिस्क की शुरुआत में होता है, VBR एक विशिष्ट पार्टीशन का पहला सेक्टर होता है। MBR OS-विशिष्ट बूटलोडर को लोड करने के लिए सक्रिय पार्टीशन के VBR को इंगित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Why is the 'CMOS Checksum Error' displayed during the POST phase?",opts:["The hard drive is physically damaged","The RAM modules are incorrectly seated","The data in the CMOS memory is corrupted, often due to a dead battery","The operating system files are deleted"],ans:2,exp:"A 'CMOS Checksum Error' implies that the data currently read from the CMOS chip does not match the expected hash. This data corruption is most frequently caused by a depleted CR2032 motherboard battery failing to maintain the memory."},hi:{q:"POST चरण के दौरान 'CMOS Checksum Error' क्यों प्रदर्शित होता है?",opts:["हार्ड ड्राइव शारीरिक रूप से क्षतिग्रस्त है","RAM मॉड्यूल गलत तरीके से बैठे हैं","CMOS मेमोरी में डेटा दूषित हो गया है, अक्सर डेड बैटरी के कारण","ऑपरेटिंग सिस्टम फ़ाइलें हटा दी गई हैं"],ans:2,exp:"'CMOS चेकसम एरर' का अर्थ है कि वर्तमान में CMOS चिप से पढ़ा गया डेटा अपेक्षित हैश से मेल नहीं खाता है। यह डेटा भ्रष्टाचार अक्सर एक समाप्त हो चुकी CR2032 मदरबोर्ड बैटरी के कारण होता है जो मेमोरी को बनाए रखने में विफल रहता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'hiberfil.sys' file facilitate during the Windows 10 boot process?",opts:["It acts as the BCD database","It stores the system memory for Fast Startup (Hybrid Boot)","It formats the hard drive","It checks for system viruses"],ans:1,exp:"In Windows 8 and 10, Fast Startup (Hybrid Boot) works by logging off users and hibernating the OS kernel session to the 'hiberfil.sys' file instead of fully shutting down. Booting from this file is significantly faster."},hi:{q:"विंडोज 10 बूट प्रक्रिया के दौरान 'hiberfil.sys' फ़ाइल क्या सुविधा प्रदान करती है?",opts:["यह BCD डेटाबेस के रूप में कार्य करता है","यह फास्ट स्टार्टअप (हाइब्रिड बूट) के लिए सिस्टम मेमोरी को स्टोर करता है","यह हार्ड ड्राइव को प्रारूपित (format) करता है","यह सिस्टम वायरस की जांच करता है"],ans:1,exp:"विंडोज 8 और 10 में, फास्ट स्टार्टअप (हाइब्रिड बूट) उपयोगकर्ताओं को लॉग ऑफ करके और पूरी तरह से बंद करने के बजाय 'hiberfil.sys' फ़ाइल में OS कर्नेल सत्र को हाइबरनेट करके काम करता है। इस फाइल से बूट करना काफी तेज होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following describes a 'Boot Sector Virus'?",opts:["A virus that infects word documents","A virus that targets the MBR or VBR to load itself before the OS","A virus that hides in the RAM indefinitely","A physical bug inside the CPU"],ans:1,exp:"A Boot Sector Virus writes its malicious code into the Master Boot Record (MBR) or Volume Boot Record (VBR). Because these sectors are executed before the OS loads, the virus gains deep control over the system extremely early."},hi:{q:"निम्नलिखित में से कौन 'बूट सेक्टर वायरस' का वर्णन करता है?",opts:["एक वायरस जो वर्ड दस्तावेज़ों को संक्रमित करता है","एक वायरस जो OS से पहले खुद को लोड करने के लिए MBR या VBR को लक्षित करता है","एक वायरस जो अनिश्चित काल तक RAM में छिपता है","CPU के अंदर एक भौतिक बग"],ans:1,exp:"एक बूट सेक्टर वायरस अपने दुर्भावनापूर्ण कोड को मास्टर बूट रिकॉर्ड (MBR) या वॉल्यूम बूट रिकॉर्ड (VBR) में लिखता है। चूँकि OS लोड होने से पहले इन सेक्टरों को निष्पादित किया जाता है, इसलिए वायरस बहुत जल्दी सिस्टम पर गहरा नियंत्रण प्राप्त कर लेता है।"}},
{type:"mcq",diff:"medium",en:{q:"In older MS-DOS environments, which file contained the core operating system logic and was required to boot?",opts:["BOOTMGR","NTLDR","IO.SYS and MSDOS.SYS","WIN.INI"],ans:2,exp:"In MS-DOS architectures (including early Windows 9x), IO.SYS (hardware interfacing) and MSDOS.SYS (kernel logic) were the hidden, fundamental system files required to initiate the OS boot sequence, along with COMMAND.COM."},hi:{q:"पुराने MS-DOS वातावरण में, किस फ़ाइल में मुख्य ऑपरेटिंग सिस्टम लॉजिक था और जिसे बूट करने के लिए आवश्यक था?",opts:["BOOTMGR","NTLDR","IO.SYS और MSDOS.SYS","WIN.INI"],ans:2,exp:"MS-DOS आर्किटेक्चर (शुरुआती विंडोज 9x सहित) में, IO.SYS (हार्डवेयर इंटरफेसिंग) और MSDOS.SYS (कर्नेल लॉजिक) छिपी हुई, मौलिक सिस्टम फ़ाइलें थीं जिन्हें COMMAND.COM के साथ ओएस बूट अनुक्रम शुरू करने के लिए आवश्यक माना जाता था।"}},
{type:"mcq",diff:"medium",en:{q:"Which command prompts the Windows PE (Preinstallation Environment) to repair a corrupt MBR?",opts:["chkdsk /f","bootrec /fixmbr","sfc /scannow","ping 127.0.0.1"],ans:1,exp:"The 'bootrec.exe' utility, available in the Windows Recovery Environment, provides the '/fixmbr' switch. This command writes a new, clean, Windows-compatible Master Boot Record to the system partition, fixing bootloader corruption."},hi:{q:"कौन सा कमांड दूषित MBR की मरम्मत के लिए विंडोज PE (प्रीइंस्टॉलेशन एनवायरनमेंट) को प्रेरित करता है?",opts:["chkdsk /f","bootrec /fixmbr","sfc /scannow","ping 127.0.0.1"],ans:1,exp:"विंडोज रिकवरी एनवायरनमेंट में उपलब्ध 'bootrec.exe' उपयोगिता '/fixmbr' स्विच प्रदान करती है। यह कमांड सिस्टम पार्टीशन में एक नया, स्वच्छ, विंडोज-संगत मास्टर बूट रिकॉर्ड लिखता है, जिससे बूटलोडर भ्रष्टाचार (corruption) ठीक हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the term 'Dual Booting' imply?",opts:["Booting a computer twice in a row","Having two monitors active during boot","Installing two separate operating systems on the same machine and choosing one at startup","Booting from two hard drives simultaneously"],ans:2,exp:"Dual Booting refers to a configuration where a single computer has two separate operating systems installed (e.g., Windows 10 and Ubuntu Linux). A bootloader menu appears at startup, allowing the user to select which OS to load."},hi:{q:"'डुअल बूटिंग' (Dual Booting) शब्द का क्या अर्थ है?",opts:["एक कंप्यूटर को लगातार दो बार बूट करना","बूट के दौरान दो मॉनिटर सक्रिय रखना","एक ही मशीन पर दो अलग-अलग ऑपरेटिंग सिस्टम स्थापित करना और स्टार्टअप पर एक को चुनना","एक साथ दो हार्ड ड्राइव से बूट करना"],ans:2,exp:"डुअल बूटिंग एक कॉन्फ़िगरेशन को संदर्भित करता है जहां एक कंप्यूटर में दो अलग-अलग ऑपरेटिंग सिस्टम स्थापित होते हैं (जैसे, विंडोज 10 और उबंटू लिनक्स)। स्टार्टअप पर एक बूटलोडर मेनू दिखाई देता है, जिससे उपयोगकर्ता यह चुन सकता है कि कौन सा OS लोड करना है।"}},
{type:"mcq",diff:"medium",en:{q:"Which configuration file does the GRUB bootloader read to display its boot menu options?",opts:["/etc/fstab","grub.cfg (or menu.lst)","boot.ini","bcd"],ans:1,exp:"In modern Linux environments running GRUB 2, the primary configuration file that determines the boot menu entries, timeout parameters, and kernel paths is located at '/boot/grub/grub.cfg'. In older GRUB legacy, it was 'menu.lst'."},hi:{q:"अपने बूट मेनू विकल्पों को प्रदर्शित करने के लिए GRUB बूटलोडर किस कॉन्फ़िगरेशन फ़ाइल को पढ़ता है?",opts:["/etc/fstab","grub.cfg (या menu.lst)","boot.ini","bcd"],ans:1,exp:"GRUB 2 चलाने वाले आधुनिक लिनक्स वातावरण में, प्राथमिक कॉन्फ़िगरेशन फ़ाइल जो बूट मेनू प्रविष्टियों, टाइमआउट मापदंडों और कर्नेल पथों को निर्धारित करती है, '/boot/grub/grub.cfg' पर स्थित होती है। पुराने GRUB लिगेसी में, यह 'menu.lst' था।"}},
{type:"mcq",diff:"medium",en:{q:"In the context of network booting, what does PXE stand for?",opts:["Preboot Execution Environment","Primary Execution Engine","Post XML Execution","Pre-extended Execution"],ans:0,exp:"PXE (Preboot Execution Environment) is an industry-standard client/server interface that allows networked computers to boot an OS directly from a server over the network, entirely bypassing local storage devices."},hi:{q:"नेटवर्क बूटिंग के संदर्भ में PXE का पूर्ण रूप क्या है?",opts:["प्रीबूट एग्जीक्यूशन एनवायरनमेंट (Preboot Execution Environment)","प्राइमरी एग्जीक्यूशन इंजन","पोस्ट एक्सएमएल एग्जीक्यूशन","प्री-एक्सटेंडेड एग्जीक्यूशन"],ans:0,exp:"PXE (प्रीबूट एग्जीक्यूशन एनवायर्नमेंट) एक उद्योग-मानक क्लाइंट/सर्वर इंटरफ़ेस है जो नेटवर्क वाले कंप्यूटरों को स्थानीय स्टोरेज उपकरणों को पूरी तरह से दरकिनार करते हुए नेटवर्क पर सीधे सर्वर से OS बूट करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What happens during the OS kernel initialization phase?",opts:["The motherboard checks the RAM","The monitor turns on","The core OS components, memory management, and drivers are loaded into RAM","The user logs into their account"],ans:2,exp:"After the bootloader executes, kernel initialization begins. During this critical phase, the OS kernel takes control over the CPU, sets up memory management structures, and loads essential system drivers required for full functionality."},hi:{q:"OS कर्नेल इनिशियलाइज़ेशन चरण के दौरान क्या होता है?",opts:["मदरबोर्ड RAM की जांच करता है","मॉनिटर चालू हो जाता है","कोर OS घटक, मेमोरी प्रबंधन और ड्राइवर RAM में लोड किए जाते हैं","उपयोगकर्ता अपने खाते में लॉग इन करता है"],ans:2,exp:"बूटलोडर के निष्पादित होने के बाद, कर्नेल इनिशियलाइज़ेशन शुरू होता है। इस महत्वपूर्ण चरण के दौरान, OS कर्नेल CPU पर नियंत्रण लेता है, मेमोरी प्रबंधन संरचनाएं स्थापित करता है, और पूर्ण कार्यक्षमता के लिए आवश्यक सिस्टम ड्राइवर लोड करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which process represents the interactive user logon interface in modern Windows versions?",opts:["wininit.exe","winlogon.exe / LogonUI.exe","explorer.exe","smss.exe"],ans:1,exp:"Winlogon.exe manages the interactive user session logon and logoff procedures. It works in conjunction with LogonUI.exe, which actually renders and displays the graphical login screen where users input their passwords."},hi:{q:"आधुनिक विंडोज़ संस्करणों में कौन सी प्रक्रिया इंटरैक्टिव उपयोगकर्ता लॉगऑन (Logon) इंटरफ़ेस का प्रतिनिधित्व करती है?",opts:["wininit.exe","winlogon.exe / LogonUI.exe","explorer.exe","smss.exe"],ans:1,exp:"Winlogon.exe इंटरैक्टिव उपयोगकर्ता सत्र लॉगऑन और लॉगऑफ़ प्रक्रियाओं का प्रबंधन करता है। यह LogonUI.exe के संयोजन के साथ काम करता है, जो वास्तव में ग्राफिकल लॉगिन स्क्रीन को प्रस्तुत और प्रदर्शित करता है जहां उपयोगकर्ता अपना पासवर्ड दर्ज करते हैं।"}},
{type:"tf",diff:"medium",en:{q:"Secure Boot is a feature of traditional BIOS that prevents unauthorized software from loading.",opts:["True","False"],ans:1,exp:"False. Secure Boot is specifically a feature introduced with the modern UEFI standard, not traditional BIOS. It uses cryptographic signatures to ensure that only trusted, digitally signed bootloaders and OS kernels can execute."},hi:{q:"सिक्योर बूट (Secure Boot) पारंपरिक BIOS की एक विशेषता है जो अनधिकृत सॉफ़्टवेयर को लोड होने से रोकती है।",opts:["सही","गलत"],ans:1,exp:"गलत। सिक्योर बूट विशेष रूप से आधुनिक UEFI मानक के साथ पेश की गई एक सुविधा है, पारंपरिक BIOS के साथ नहीं। यह यह सुनिश्चित करने के लिए क्रिप्टोग्राफ़िक हस्ताक्षरों का उपयोग करता है कि केवल विश्वसनीय, डिजिटल रूप से हस्ताक्षरित बूटलोडर और OS कर्नेल ही निष्पादित हो सकें।"}},
{type:"tf",diff:"medium",en:{q:"An active partition is strictly required on an MBR disk to indicate which partition contains the bootloader.",opts:["True","False"],ans:0,exp:"True. On an MBR formatted disk, exactly one primary partition must be flagged as 'Active'. The Master Boot Record (MBR) code looks for this flag to determine which Volume Boot Record (VBR) to load in order to start the OS."},hi:{q:"MBR डिस्क पर एक सक्रिय पार्टीशन (Active partition) का होना सख्त आवश्यक है ताकि यह इंगित किया जा सके कि किस पार्टीशन में बूटलोडर है।",opts:["सही","गलत"],ans:0,exp:"सही। MBR स्वरूपित डिस्क पर, ठीक एक प्राथमिक पार्टीशन को 'सक्रिय' (Active) के रूप में चिह्नित किया जाना चाहिए। OS शुरू करने के लिए किस वॉल्यूम बूट रिकॉर्ड (VBR) को लोड करना है, यह निर्धारित करने के लिए MBR कोड इस ध्वज (flag) को खोजता है।"}},
{type:"mcq",diff:"hard",en:{q:"At what specific physical memory address does an x86 processor begin executing instructions immediately after being powered on?",opts:["0x00000000","0x000FFFF0","0xFFFFFFF0","0x00100000"],ans:2,exp:"Immediately after a hardware reset or power-on, an x86 architecture CPU fundamentally starts executing instructions at physical memory address 0xFFFFFFF0, known as the Reset Vector, mapped directly to the motherboard's ROM BIOS."},hi:{q:"चालू होने के तुरंत बाद एक x86 प्रोसेसर किस विशिष्ट भौतिक मेमोरी एड्रेस पर निर्देशों को निष्पादित करना शुरू करता है?",opts:["0x00000000","0x000FFFF0","0xFFFFFFF0","0x00100000"],ans:2,exp:"हार्डवेयर रीसेट या पावर-ऑन के तुरंत बाद, एक x86 आर्किटेक्चर CPU मूल रूप से भौतिक मेमोरी एड्रेस 0xFFFFFFF0 पर निर्देशों को निष्पादित करना शुरू करता है, जिसे रीसेट वेक्टर (Reset Vector) कहा जाता है, जिसे सीधे मदरबोर्ड के ROM BIOS में मैप किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the two-byte hexadecimal signature located at the very end of a valid Master Boot Record (MBR)?",opts:["0x0000","0xAA55","0xFFFF","0xDEAD"],ans:1,exp:"The boot signature resides at byte offsets 510 and 511 of the 512-byte MBR sector. The exact hexadecimal sequence is 0x55 0xAA. If the BIOS does not find this signature, it concludes the drive is not bootable."},hi:{q:"वैध मास्टर बूट रिकॉर्ड (MBR) के बिल्कुल अंत में स्थित दो-बाइट हेक्साडेसिमल सिग्नेचर (हस्ताक्षर) क्या है?",opts:["0x0000","0xAA55","0xFFFF","0xDEAD"],ans:1,exp:"बूट सिग्नेचर 512-बाइट MBR सेक्टर के बाइट ऑफसेट 510 और 511 पर रहता है। सटीक हेक्साडेसिमल अनुक्रम 0x55 0xAA (लिटिल-एंडियन के रूप में 0xAA55) है। यदि BIOS को यह हस्ताक्षर नहीं मिलता है, तो यह निष्कर्ष निकालता है कि ड्राइव बूटेबल नहीं है।"}},
{type:"mcq",diff:"hard",en:{q:"How many bytes are dedicated exclusively to the executable Bootstrap Code area within the standard 512-byte MBR sector?",opts:["64 bytes","446 bytes","510 bytes","16 bytes"],ans:1,exp:"Within the standard 512-byte MBR, exactly 446 bytes are reserved for the executable bootstrap code. The remaining bytes are split into 64 bytes for the 4-entry partition table and 2 bytes for the boot signature."},hi:{q:"मानक 512-बाइट MBR सेक्टर के भीतर निष्पादन योग्य बूटस्ट्रैप कोड क्षेत्र (Bootstrap Code area) के लिए विशेष रूप से कितने बाइट्स समर्पित हैं?",opts:["64 बाइट्स","446 बाइट्स","510 बाइट्स","16 बाइट्स"],ans:1,exp:"मानक 512-बाइट MBR के भीतर, ठीक 446 बाइट्स निष्पादन योग्य बूटस्ट्रैप कोड के लिए आरक्षित हैं। शेष बाइट्स 4-प्रविष्टि पार्टीशन टेबल के लिए 64 बाइट्स और बूट हस्ताक्षर के लिए 2 बाइट्स में विभाजित हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which registry hive does the BOOTMGR primarily read to load the Windows Boot Configuration Data (BCD)?",opts:["HKEY_CURRENT_USER","HKEY_LOCAL_MACHINE\\SYSTEM","HKEY_LOCAL_MACHINE\\BCD00000000","HKEY_CLASSES_ROOT"],ans:2,exp:"The Boot Configuration Data (BCD) is essentially a registry hive. During the boot process, BOOTMGR mounts and reads this data from the BCD store file, which is mapped internally to HKEY_LOCAL_MACHINE\\BCD00000000."},hi:{q:"विंडोज बूट कॉन्फ़िगरेशन डेटा (BCD) को लोड करने के लिए BOOTMGR मुख्य रूप से किस रजिस्ट्री हाइव (registry hive) को पढ़ता है?",opts:["HKEY_CURRENT_USER","HKEY_LOCAL_MACHINE\\SYSTEM","HKEY_LOCAL_MACHINE\\BCD00000000","HKEY_CLASSES_ROOT"],ans:2,exp:"बूट कॉन्फ़िगरेशन डेटा (BCD) अनिवार्य रूप से एक रजिस्ट्री हाइव है। बूट प्रक्रिया के दौरान, BOOTMGR BCD स्टोर फ़ाइल से इस डेटा को माउंट करता है और पढ़ता है, जिसे आंतरिक रूप से HKEY_LOCAL_MACHINE\\BCD00000000 पर मैप किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What file system is strictly required by the UEFI specification for the EFI System Partition (ESP)?",opts:["NTFS","EXT4","FAT32","exFAT"],ans:2,exp:"The UEFI specification explicitly mandates that the EFI System Partition (ESP), which contains the EFI bootloaders (.efi files) for installed operating systems, must be formatted entirely using the FAT32 file system."},hi:{q:"EFI सिस्टम पार्टीशन (ESP) के लिए UEFI विशिष्टता (specification) द्वारा किस फ़ाइल सिस्टम की सख्ती से आवश्यकता है?",opts:["NTFS","EXT4","FAT32","exFAT"],ans:2,exp:"UEFI विशिष्टता स्पष्ट रूप से अनिवार्य करती है कि EFI सिस्टम पार्टीशन (ESP), जिसमें स्थापित ऑपरेटिंग सिस्टम के लिए EFI बूटलोडर (.efi फ़ाइलें) शामिल हैं, को पूरी तरह से FAT32 फ़ाइल सिस्टम का उपयोग करके स्वरूपित किया जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"In a GPT partitioning scheme, at which Logical Block Address (LBA) does the Primary Partition Table Header reside?",opts:["LBA 0","LBA 1","LBA 2","LBA 34"],ans:1,exp:"In a GUID Partition Table (GPT) layout, LBA 0 contains the 'Protective MBR' for legacy compatibility. The actual GPT Primary Header resides strictly at LBA 1, immediately followed by the partition entry arrays starting at LBA 2."},hi:{q:"GPT पार्टीशनिंग योजना में, प्राइमरी पार्टीशन टेबल हेडर किस लॉजिकल ब्लॉक एड्रेस (LBA) पर रहता है?",opts:["LBA 0","LBA 1","LBA 2","LBA 34"],ans:1,exp:"GUID पार्टीशन टेबल (GPT) लेआउट में, LBA 0 में विरासत अनुकूलता (legacy compatibility) के लिए 'प्रोटेक्टिव MBR' होता है। वास्तविक GPT प्राइमरी हेडर सख्ती से LBA 1 पर रहता है, जिसके तुरंत बाद LBA 2 से शुरू होने वाली पार्टीशन प्रविष्टि सरणियाँ होती हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is the hexadecimal value assigned to the partition type flag in an MBR partition table to mark a partition as 'Active'?",opts:["0x00","0x80","0x55","0xEE"],ans:1,exp:"Within the 16-byte structure of an MBR partition entry, the very first byte specifies the boot indicator (status). A hexadecimal value of 0x80 declares the partition as bootable/active, while 0x00 declares it non-bootable."},hi:{q:"पार्टीशन को 'सक्रिय' (Active) के रूप में चिह्नित करने के लिए MBR पार्टीशन टेबल में पार्टीशन प्रकार ध्वज (flag) को सौंपा गया हेक्साडेसिमल मान क्या है?",opts:["0x00","0x80","0x55","0xEE"],ans:1,exp:"MBR पार्टीशन प्रविष्टि की 16-बाइट संरचना के भीतर, सबसे पहला बाइट बूट संकेतक (स्थिति) निर्दिष्ट करता है। 0x80 का हेक्साडेसिमल मान पार्टीशन को बूटेबल/सक्रिय घोषित करता है, जबकि 0x00 इसे गैर-बूटेबल घोषित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which hardware port does the BIOS typically output POST hexadecimal checkpoint codes to for debugging via an add-on diagnostic card?",opts:["Port 80h","Port 21h","COM1","LPT1"],ans:0,exp:"During the POST sequence, the BIOS continuously outputs two-digit hexadecimal progress codes (checkpoint codes) to I/O Port 80h. Technicians use specialized POST diagnostic PCI/ISA cards displaying these numbers to identify exact hardware failure points."},hi:{q:"ऐड-ऑन डायग्नोस्टिक कार्ड के माध्यम से डिबगिंग के लिए BIOS आमतौर पर किस हार्डवेयर पोर्ट पर POST हेक्साडेसिमल चेकपॉइंट कोड आउटपुट करता है?",opts:["पोर्ट 80h (Port 80h)","पोर्ट 21h","COM1","LPT1"],ans:0,exp:"POST अनुक्रम के दौरान, BIOS I/O पोर्ट 80h पर लगातार दो अंकों के हेक्साडेसिमल प्रगति कोड (चेकपॉइंट कोड) आउटपुट करता है। तकनीशियन सटीक हार्डवेयर विफलता बिंदुओं की पहचान करने के लिए इन नंबरों को प्रदर्शित करने वाले विशेष POST डायग्नोस्टिक PCI/ISA कार्ड का उपयोग करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is the primary role of GRUB's 'Stage 1.5' in older Linux boot processes?",opts:["To load the Linux kernel directly","To provide file system drivers to read Stage 2","To display the graphical splash screen","To initialize the CPU registers"],ans:1,exp:"In legacy GRUB, Stage 1 (residing in the tiny MBR) lacked the capacity to understand file systems. Stage 1.5, embedded in the space between the MBR and the first partition, provided file system drivers required to locate and load the much larger Stage 2 from the partition."},hi:{q:"पुरानी लिनक्स बूट प्रक्रियाओं में GRUB के 'स्टेज 1.5' की प्राथमिक भूमिका क्या है?",opts:["लिनक्स कर्नेल को सीधे लोड करने के लिए","स्टेज 2 पढ़ने के लिए फाइल सिस्टम ड्राइवर प्रदान करने के लिए","ग्राफिकल स्पलैश स्क्रीन प्रदर्शित करने के लिए","CPU रजिस्टरों को प्रारंभ करने के लिए"],ans:1,exp:"लिगेसी GRUB में, स्टेज 1 (जो छोटे MBR में रहता है) में फ़ाइल सिस्टम को समझने की क्षमता का अभाव था। MBR और पहले पार्टीशन के बीच की जगह में एम्बेडेड स्टेज 1.5, पार्टीशन से बहुत बड़े स्टेज 2 का पता लगाने और लोड करने के लिए आवश्यक फ़ाइल सिस्टम ड्राइवर प्रदान करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In UEFI, what is the 'Platform Key' (PK) primarily utilized for?",opts:["Encrypting the hard drive","Establishing the Root of Trust for Secure Boot","Validating Windows product keys","Managing user passwords"],ans:1,exp:"In the UEFI Secure Boot architecture, the Platform Key (PK) establishes the ultimate Root of Trust. It secures the firmware layer, ensuring that updates to the Key Exchange Key (KEK) and allowed signature databases (db) are cryptographically authenticated by the hardware owner."},hi:{q:"UEFI में, 'प्लेटफॉर्म की' (PK) का उपयोग मुख्य रूप से किस लिए किया जाता है?",opts:["हार्ड ड्राइव को एन्क्रिप्ट करने के लिए","सिक्योर बूट के लिए रूट ऑफ ट्रस्ट स्थापित करने के लिए","विंडोज उत्पाद कुंजी (product keys) मान्य करने के लिए","उपयोगकर्ता पासवर्ड प्रबंधित करने के लिए"],ans:1,exp:"UEFI सिक्योर बूट आर्किटेक्चर में, प्लेटफ़ॉर्म कुंजी (PK) अंतिम रूट ऑफ़ ट्रस्ट स्थापित करती है। यह फर्मवेयर परत को सुरक्षित करता है, यह सुनिश्चित करता है कि कुंजी विनिमय कुंजी (KEK) और अनुमत हस्ताक्षर डेटाबेस (db) के अपडेट हार्डवेयर मालिक द्वारा क्रिप्टोग्राफ़िक रूप से प्रमाणित हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Ntoskrnl.exe initialization is split into two phases. What happens during Phase 0?",opts:["Loading of the graphical user interface","Hardware interrupts are disabled and core data structures are initialized","Network drivers are activated","The paging file is created"],ans:1,exp:"Windows kernel (Ntoskrnl.exe) initialization occurs in Phase 0 and Phase 1. In Phase 0, hardware interrupts are strictly disabled. The kernel builds the absolute core internal data structures, initializes the memory manager, and prepares the hardware for Phase 1 where interrupts are enabled."},hi:{q:"Ntoskrnl.exe इनिशियलाइज़ेशन को दो चरणों में विभाजित किया गया है। चरण 0 (Phase 0) के दौरान क्या होता है?",opts:["ग्राफिकल यूजर इंटरफेस की लोडिंग","हार्डवेयर इंटरप्ट अक्षम (disabled) होते हैं और कोर डेटा संरचनाएं प्रारंभ की जाती हैं","नेटवर्क ड्राइवर सक्रिय हो जाते हैं","पेजिंग फ़ाइल बनाई जाती है"],ans:1,exp:"विंडोज़ कर्नेल (Ntoskrnl.exe) इनिशियलाइज़ेशन चरण 0 और चरण 1 में होता है। चरण 0 में, हार्डवेयर इंटरप्ट को सख्ती से अक्षम किया जाता है। कर्नेल पूर्ण कोर आंतरिक डेटा संरचनाओं का निर्माण करता है, मेमोरी मैनेजर को प्रारंभ करता है, और चरण 1 के लिए हार्डवेयर तैयार करता है जहाँ इंटरप्ट सक्षम होते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following accurately describes the Windows 10 'winload.efi' execution context?",opts:["It runs in Real Mode (16-bit)","It executes in the UEFI pre-boot environment (boot services)","It runs in user-mode inside the OS","It operates exclusively in the DOS environment"],ans:1,exp:"Unlike the legacy winload.exe which ran via BIOS interrupts, 'winload.efi' executes specifically within the UEFI environment natively utilizing UEFI Boot Services. It maps the kernel into memory and sets up the transition to the OS runtime before calling ExitBootServices()."},hi:{q:"निम्नलिखित में से कौन विंडोज 10 'winload.efi' निष्पादन संदर्भ का सटीक वर्णन करता है?",opts:["यह रियल मोड (16-बिट) में चलता है","यह UEFI प्री-बूट वातावरण (बूट सेवाओं) में निष्पादित होता है","यह OS के अंदर यूजर-मोड में चलता है","यह विशेष रूप से DOS वातावरण में संचालित होता है"],ans:1,exp:"लीगेसी winload.exe के विपरीत जो BIOS इंटरप्ट के माध्यम से चलता था, 'winload.efi' विशेष रूप से UEFI वातावरण के भीतर निष्पादित होता है जो मूल रूप से UEFI बूट सेवाओं का उपयोग करता है। यह कर्नेल को मेमोरी में मैप करता है और ExitBootServices() को कॉल करने से पहले OS रनटाइम में संक्रमण (transition) स्थापित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a standard modern GPT architecture, what natively represents the absolute maximum number of primary partitions permitted on a disk under Windows?",opts:["4","24","128","Unlimited"],ans:2,exp:"While the GPT specification itself can support arbitrary partition table sizes, the Microsoft Windows implementation inherently sets the GPT size limit to accommodate a maximum of exactly 128 primary partitions per physical hard drive."},hi:{q:"एक मानक आधुनिक GPT आर्किटेक्चर में, विंडोज के तहत एक डिस्क पर अनुमत प्राथमिक पार्टीशन की पूर्ण अधिकतम संख्या क्या है?",opts:["4","24","128","असीमित (Unlimited)"],ans:2,exp:"जबकि GPT विशिष्टता (specification) स्वयं मनमाने पार्टीशन टेबल आकार का समर्थन कर सकती है, Microsoft Windows कार्यान्वयन स्वाभाविक रूप से प्रति भौतिक हार्ड ड्राइव में ठीक 128 प्राथमिक पार्टीशन को समायोजित करने के लिए GPT आकार सीमा निर्धारित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which core Windows subsystem is executed by smss.exe during the boot process to handle Win32 API calls?",opts:["csrss.exe","svchost.exe","lsass.exe","services.exe"],ans:0,exp:"The Session Manager (smss.exe) initiates 'csrss.exe' (Client/Server Runtime Subsystem). Csrss is the crucial user-mode component of the Windows subsystem that handles console windows, creating/deleting threads, and processing 16-bit virtual DOS machine environments."},hi:{q:"Win32 API कॉल को संभालने के लिए बूट प्रक्रिया के दौरान smss.exe द्वारा कौन सा मुख्य Windows सबसिस्टम निष्पादित किया जाता है?",opts:["csrss.exe","svchost.exe","lsass.exe","services.exe"],ans:0,exp:"सत्र प्रबंधक (smss.exe) 'csrss.exe' (क्लाइंट/सर्वर रनटाइम सबसिस्टम) शुरू करता है। Csrss विंडोज़ सबसिस्टम का महत्वपूर्ण उपयोगकर्ता-मोड घटक है जो कंसोल विंडो, थ्रेड्स बनाने/हटाने और 16-बिट वर्चुअल DOS मशीन वातावरण को संभालने का काम करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically happens when a Windows system transitions from 'ntoskrnl.exe' execution to 'smss.exe'?",opts:["The OS transitions from kernel-mode initialization to user-mode subsystem setup","The hardware POST sequence concludes","The network layer is reset","The GUI is completely loaded and ready for interaction"],ans:0,exp:"Ntoskrnl.exe represents the core kernel-mode execution. When it launches smss.exe (Session Manager Subsystem), it marks the critical system transition boundary from purely Ring-0 kernel-mode initialization to the beginning of Ring-3 user-mode process setup."},hi:{q:"विशेष रूप से क्या होता है जब कोई विंडोज सिस्टम 'ntoskrnl.exe' निष्पादन से 'smss.exe' में संक्रमण (transitions) करता है?",opts:["OS कर्नेल-मोड इनिशियलाइज़ेशन से यूजर-मोड सबसिस्टम सेटअप में बदल जाता है","हार्डवेयर POST अनुक्रम समाप्त हो जाता है","नेटवर्क परत रीसेट हो जाती है","GUI पूरी तरह से लोड हो जाता है और इंटरैक्शन के लिए तैयार हो जाता है"],ans:0,exp:"Ntoskrnl.exe मुख्य कर्नेल-मोड निष्पादन का प्रतिनिधित्व करता है। जब यह smss.exe (सत्र प्रबंधक उपप्रणाली) लॉन्च करता है, तो यह विशुद्ध रूप से रिंग-0 कर्नेल-मोड इनिशियलाइज़ेशन से रिंग-3 उपयोगकर्ता-मोड प्रक्रिया सेटअप की शुरुआत तक महत्वपूर्ण सिस्टम संक्रमण सीमा को चिह्नित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a technician runs 'bcdboot c:\\windows' via command prompt in Windows PE, what does this command accomplish?",opts:["It formats the C: drive","It copies critical boot files from the Windows directory to the active system partition and creates a new BCD store","It uninstalls the bootloader","It bypasses the BIOS password"],ans:1,exp:"The BCDBoot utility is used to repair or initialize the boot environment. Running 'bcdboot c:\\windows' actively copies the necessary boot environment files (like bootmgr) from the installed Windows image to the system partition and generates a fresh BCD configuration."},hi:{q:"यदि कोई तकनीशियन विंडोज PE में कमांड प्रॉम्प्ट के माध्यम से 'bcdboot c:\\windows' चलाता है, तो यह कमांड क्या पूरा करता है?",opts:["यह C: ड्राइव को फॉर्मेट करता है","यह विंडोज डायरेक्टरी से सक्रिय सिस्टम पार्टीशन में महत्वपूर्ण बूट फाइलों को कॉपी करता है और एक नया BCD स्टोर बनाता है","यह बूटलोडर को अनइंस्टॉल करता है","यह BIOS पासवर्ड को बायपास करता है"],ans:1,exp:"BCDBoot उपयोगिता का उपयोग बूट वातावरण की मरम्मत या आरंभीकरण के लिए किया जाता है। 'bcdboot c:\\windows' चलाने से स्थापित विंडोज इमेज से आवश्यक बूट वातावरण फाइलें (जैसे bootmgr) सक्रिय सिस्टम पार्टीशन में सक्रिय रूप से कॉपी हो जाती हैं और एक नया BCD कॉन्फ़िगरेशन उत्पन्न होता है।"}},
{type:"mcq",diff:"hard",en:{q:"What size is the typical classic CMOS RAM used to store BIOS parameters on legacy motherboards?",opts:["1 Megabyte","512 bytes","64 bytes","4 Kilobytes"],ans:2,exp:"In legacy IBM PC architectures, the Motorola MC146818 RTC/CMOS chip provided exactly 64 bytes of volatile battery-backed memory. Only 14 bytes were used for the Real Time Clock, leaving a mere 50 bytes for storing BIOS hardware parameters."},hi:{q:"विरासत (legacy) मदरबोर्ड पर BIOS मापदंडों को संग्रहीत करने के लिए उपयोग किए जाने वाले सामान्य क्लासिक CMOS RAM का आकार क्या है?",opts:["1 मेगाबाइट","512 बाइट्स","64 बाइट्स","4 किलोबाइट्स"],ans:2,exp:"लिगेसी IBM PC आर्किटेक्चर में, मोटोरोला MC146818 RTC/CMOS चिप ने ठीक 64 बाइट्स की अस्थिर बैटरी-समर्थित मेमोरी प्रदान की। रीयल टाइम क्लॉक के लिए केवल 14 बाइट्स का उपयोग किया गया था, जिससे BIOS हार्डवेयर मापदंडों को संग्रहीत करने के लिए केवल 50 बाइट्स बचे थे।"}},
{type:"mcq",diff:"hard",en:{q:"Which Linux boot parameter explicitly forces the kernel to print extremely detailed debug output during the boot sequence?",opts:["quiet","splash","debug","init=/bin/bash"],ans:2,exp:"When editing the GRUB boot parameters, appending the 'debug' directive instructs the Linux kernel to increase its logging verbosity to the maximum level. This pushes detailed debugging messages to the console during boot, essential for diagnosing kernel panics."},hi:{q:"कौन सा लिनक्स बूट पैरामीटर स्पष्ट रूप से कर्नेल को बूट अनुक्रम के दौरान अत्यंत विस्तृत डिबग आउटपुट प्रिंट करने के लिए मजबूर करता है?",opts:["quiet","splash","debug","init=/bin/bash"],ans:2,exp:"GRUB बूट मापदंडों को संपादित करते समय, 'debug' निर्देश जोड़ने से लिनक्स कर्नेल को अपने लॉगिंग वर्बोसिटी को अधिकतम स्तर तक बढ़ाने का निर्देश मिलता है। यह बूट के दौरान कंसोल पर विस्तृत डिबगिंग संदेश धकेलता है, जो कर्नेल पैनिक के निदान के लिए आवश्यक है।"}},
{type:"mcq",diff:"hard",en:{q:"In older systems, how does the MBR partition table denote a partition formatted using the NTFS file system?",opts:["Type 0x07","Type 0x82","Type 0x83","Type 0x0C"],ans:0,exp:"In the MBR partition table standard, the byte describing the partition type defines the expected file system. A hex value of 0x07 specifically indicates an HPFS/NTFS/exFAT partition type, enabling the OS to load the correct driver."},hi:{q:"पुराने सिस्टम में, MBR पार्टीशन टेबल NTFS फ़ाइल सिस्टम का उपयोग करके स्वरूपित पार्टीशन को कैसे दर्शाता है?",opts:["टाइप 0x07","टाइप 0x82","टाइप 0x83","टाइप 0x0C"],ans:0,exp:"MBR पार्टीशन टेबल मानक में, पार्टीशन प्रकार का वर्णन करने वाला बाइट अपेक्षित फ़ाइल सिस्टम को परिभाषित करता है। 0x07 का एक हेक्स मान विशेष रूप से HPFS/NTFS/exFAT पार्टीशन प्रकार को इंगित करता है, जिससे OS को सही ड्राइवर लोड करने में सक्षम बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which specific Windows registry hive is exclusively loaded into memory during the earliest boot phases (by the bootloader) to locate critical device drivers before the full OS loads?",opts:["SOFTWARE","SAM","SYSTEM","SECURITY"],ans:2,exp:"The HKEY_LOCAL_MACHINE\\SYSTEM hive is absolutely critical for booting. The bootloader (like NTLDR or BOOTMGR) explicitly loads the 'SYSTEM' hive file into RAM because it contains the 'ControlSet' indicating which boot-start drivers (like SATA/NVMe controllers) must be initialized immediately."},hi:{q:"कौन सा विशिष्ट विंडोज रजिस्ट्री हाइव विशेष रूप से शुरुआती बूट चरणों (बूटलोडर द्वारा) के दौरान मेमोरी में लोड किया जाता है ताकि पूर्ण ओएस लोड होने से पहले महत्वपूर्ण डिवाइस ड्राइवरों का पता लगाया जा सके?",opts:["SOFTWARE","SAM","SYSTEM","SECURITY"],ans:2,exp:"HKEY_LOCAL_MACHINE\\SYSTEM हाइव बूटिंग के लिए अत्यंत महत्वपूर्ण है। बूटलोडर (जैसे NTLDR या BOOTMGR) स्पष्ट रूप से 'SYSTEM' हाइव फ़ाइल को RAM में लोड करता है क्योंकि इसमें 'ControlSet' होता है जो दर्शाता है कि किन बूट-स्टार्ट ड्राइवरों (जैसे SATA/NVMe कंट्रोलर) को तुरंत इनिशियलाइज़ किया जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"When executing a 'Soft Boot' via hardware abstraction layer software request (like clicking Restart), which CPU pin is traditionally pulled low to trigger the reset?",opts:["INTR","RESET","NMI","HOLD"],ans:1,exp:"A software-initiated restart eventually writes to specific ACPI hardware registers or a keyboard controller port (like port 64h), which physically pulls the CPU's RESET pin (or equivalent chipset line) logic low. This forcefully resets the CPU state vector without completely dropping motherboard power."},hi:{q:"हार्डवेयर एब्स्ट्रैक्शन लेयर सॉफ़्टवेयर अनुरोध (जैसे रीस्टार्ट पर क्लिक करना) के माध्यम से 'सॉफ्ट बूट' (Soft Boot) निष्पादित करते समय, रीसेट को ट्रिगर करने के लिए पारंपरिक रूप से किस CPU पिन को 'लो' (low) खींचा जाता है?",opts:["INTR","RESET","NMI","HOLD"],ans:1,exp:"एक सॉफ़्टवेयर-आरंभित पुनरारंभ अंततः विशिष्ट ACPI हार्डवेयर रजिस्टर या कीबोर्ड नियंत्रक पोर्ट (जैसे पोर्ट 64h) पर लिखता है, जो भौतिक रूप से CPU के RESET पिन (या समतुल्य चिपसेट लाइन) लॉजिक को लो (low) खींचता है। यह मदरबोर्ड की पावर को पूरी तरह से गिराए बिना CPU स्टेट वेक्टर को बलपूर्वक रीसेट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a Unified Extensible Firmware Interface (UEFI) environment, what handles the equivalent task of the legacy Master Boot Record bootstrap code?",opts:["The Protective MBR","EFI Boot Services executing a .efi bootloader application","The BIOS parameter block","Ntoskrnl directly"],ans:1,exp:"UEFI entirely deprecates the execution of 16-bit MBR bootstrap code. Instead, the UEFI firmware contains its own 'Boot Services' environment capable of natively reading FAT32 file systems. It directly locates and executes a compiled EFI application (like bootmgfw.efi) from the EFI System Partition."},hi:{q:"यूनिफाइड एक्सटेंसिबल फर्मवेयर इंटरफेस (UEFI) वातावरण में, विरासत मास्टर बूट रिकॉर्ड बूटस्ट्रैप कोड के समकक्ष कार्य को कौन संभालता है?",opts:["प्रोटेक्टिव MBR","एक .efi बूटलोडर एप्लिकेशन को निष्पादित करने वाली EFI बूट सेवाएँ","BIOS पैरामीटर ब्लॉक","Ntoskrnl सीधे"],ans:1,exp:"UEFI 16-बिट MBR बूटस्ट्रैप कोड के निष्पादन को पूरी तरह से हटा देता है। इसके बजाय, UEFI फर्मवेयर में अपना 'बूट सर्विसेज' वातावरण होता है जो FAT32 फ़ाइल सिस्टम को मूल रूप से पढ़ने में सक्षम होता है। यह EFI सिस्टम पार्टीशन से सीधे संकलित EFI एप्लिकेशन (जैसे bootmgfw.efi) का पता लगाता है और निष्पादित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which utility executes the 'lsass.exe' process during the final stages of the Windows Boot process?",opts:["winlogon.exe","smss.exe","explorer.exe","csrss.exe"],ans:0,exp:"During the later stages of Windows user-mode initialization, 'winlogon.exe' starts 'lsass.exe' (Local Security Authority Subsystem Service). LSASS handles the stringent security policy enforcement, user authentication, and creates the access tokens once the user inputs their credentials."},hi:{q:"विंडोज बूट प्रक्रिया के अंतिम चरणों के दौरान कौन सी उपयोगिता 'lsass.exe' प्रक्रिया को निष्पादित करती है?",opts:["winlogon.exe","smss.exe","explorer.exe","csrss.exe"],ans:0,exp:"विंडोज़ उपयोगकर्ता-मोड इनिशियलाइज़ेशन के बाद के चरणों के दौरान, 'winlogon.exe' 'lsass.exe' (लोकल सिक्योरिटी अथॉरिटी सबसिस्टम सर्विस) शुरू करता है। LSASS कड़ी सुरक्षा नीति प्रवर्तन, उपयोगकर्ता प्रमाणीकरण को संभालता है, और उपयोगकर्ता द्वारा अपनी साख (credentials) इनपुट करने के बाद एक्सेस टोकन बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically happens if you remove the 'quiet' and 'splash' parameters from the GRUB linux bootline?",opts:["The system boots directly into a GUI without checking disks","The system refuses to boot entirely","The boot process displays a verbose scrolling text of kernel initialization messages","The bootloader prompts for an encryption key"],ans:2,exp:"The 'quiet' parameter suppresses the majority of kernel boot messages, and 'splash' displays a graphical logo covering the terminal. Removing both forces the Linux kernel to output detailed, verbose initialization text chronologically as hardware and drivers load, which is critical for debugging."},hi:{q:"यदि आप GRUB लिनक्स बूटलाइन से 'quiet' और 'splash' पैरामीटर हटाते हैं तो विशेष रूप से क्या होता है?",opts:["सिस्टम डिस्क की जाँच किए बिना सीधे GUI में बूट होता है","सिस्टम पूरी तरह से बूट होने से इनकार करता है","बूट प्रक्रिया कर्नेल इनिशियलाइज़ेशन संदेशों का एक वर्बोस स्क्रॉलिंग टेक्स्ट प्रदर्शित करती है","बूटलोडर एन्क्रिप्शन कुंजी (Key) के लिए संकेत देता है"],ans:2,exp:"'quiet' पैरामीटर अधिकांश कर्नेल बूट संदेशों को दबा देता है, और 'splash' टर्मिनल को कवर करने वाला एक ग्राफिकल लोगो प्रदर्शित करता है। दोनों को हटाने से लिनक्स कर्नेल विस्तृत, वर्बोस इनिशियलाइज़ेशन टेक्स्ट को कालानुक्रमिक रूप से आउटपुट करने के लिए मजबूर होता है क्योंकि हार्डवेयर और ड्राइवर लोड होते हैं, जो डिबगिंग के लिए महत्वपूर्ण है।"}},
{type:"mcq",diff:"hard",en:{q:"In early DOS systems, what was the exact sequential execution order of the core system files during a boot sequence?",opts:["COMMAND.COM -> IO.SYS -> MSDOS.SYS","IO.SYS -> MSDOS.SYS -> CONFIG.SYS -> COMMAND.COM","MSDOS.SYS -> COMMAND.COM -> IO.SYS","CONFIG.SYS -> IO.SYS -> COMMAND.COM"],ans:1,exp:"The precise MS-DOS boot execution sequence initiates with the boot sector loading IO.SYS (the hardware interface layer). IO.SYS then loads MSDOS.SYS (the DOS kernel logic). Next, the system parses CONFIG.SYS to load device drivers, and finally executes COMMAND.COM (the command-line interpreter shell)."},hi:{q:"शुरुआती DOS सिस्टम में, बूट अनुक्रम के दौरान कोर सिस्टम फ़ाइलों का सटीक अनुक्रमिक निष्पादन क्रम क्या था?",opts:["COMMAND.COM -> IO.SYS -> MSDOS.SYS","IO.SYS -> MSDOS.SYS -> CONFIG.SYS -> COMMAND.COM","MSDOS.SYS -> COMMAND.COM -> IO.SYS","CONFIG.SYS -> IO.SYS -> COMMAND.COM"],ans:1,exp:"सटीक MS-DOS बूट निष्पादन अनुक्रम बूट सेक्टर लोडिंग IO.SYS (हार्डवेयर इंटरफ़ेस परत) के साथ शुरू होता है। इसके बाद IO.SYS MSDOS.SYS (DOS कर्नेल लॉजिक) को लोड करता है। अगला, सिस्टम डिवाइस ड्राइवरों को लोड करने के लिए CONFIG.SYS को पार्स करता है, और अंत में COMMAND.COM (कमांड-लाइन दुभाषिया शेल) निष्पादित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What characterizes the 'S4' ACPI power state natively utilized by the Windows Fast Startup feature?",opts:["Power On (Working State)","Sleep (Suspend to RAM)","Hibernation (Suspend to Disk)","Soft Off"],ans:2,exp:"The Advanced Configuration and Power Interface (ACPI) defines 'S4' as the Hibernation state (Suspend to Disk). In Windows Fast Startup, instead of shutting down into 'S5' (Soft Off), the system closes user sessions but suspends the kernel session state to disk (hiberfil.sys) using the S4 state mechanics."},hi:{q:"विंडोज फास्ट स्टार्टअप सुविधा द्वारा मूल रूप से उपयोग की जाने वाली 'S4' ACPI पावर अवस्था (Power state) की क्या विशेषता है?",opts:["पावर ऑन (वर्किंग स्टेट)","स्लीप (सस्पेंड टू रैम)","हाइबरनेशन (सस्पेंड टू डिस्क)","सॉफ्ट ऑफ"],ans:2,exp:"उन्नत कॉन्फ़िगरेशन और पावर इंटरफ़ेस (ACPI) 'S4' को हाइबरनेशन स्टेट (सस्पेंड टू डिस्क) के रूप में परिभाषित करता है। विंडोज फास्ट स्टार्टअप में, 'S5' (सॉफ्ट ऑफ) में बंद होने के बजाय, सिस्टम उपयोगकर्ता सत्र बंद कर देता है लेकिन S4 राज्य यांत्रिकी का उपयोग करके कर्नेल सत्र स्थिति को डिस्क (hiberfil.sys) पर निलंबित कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a system exhibits a 'Bootmgr is compressed' error, which attribute flag has been mistakenly applied to the system partition?",opts:["Hidden","Read-only","NTFS File Compression","System"],ans:2,exp:"The 'Bootmgr is compressed' error arises strictly because the NTFS file compression attribute has been erroneously applied to the entire root directory of the active partition. The BOOTMGR executable relies on a very primitive driver early in the boot sequence that lacks the computational logic to decompress itself dynamically."},hi:{q:"यदि सिस्टम 'Bootmgr is compressed' त्रुटि प्रदर्शित करता है, तो सिस्टम पार्टीशन पर गलती से कौन सा एट्रिब्यूट ध्वज (attribute flag) लागू किया गया है?",opts:["हिडन (Hidden)","रीड-ओनली (Read-only)","NTFS फ़ाइल संपीड़न (NTFS File Compression)","सिस्टम (System)"],ans:2,exp:"'Bootmgr is compressed' त्रुटि कड़ाई से उत्पन्न होती है क्योंकि NTFS फ़ाइल संपीड़न (compression) एट्रिब्यूट को गलती से सक्रिय पार्टीशन की संपूर्ण रूट डायरेक्टरी में लागू कर दिया गया है। BOOTMGR बूट अनुक्रम में बहुत जल्दी एक आदिम ड्राइवर पर निर्भर करता है जिसमें स्वयं को गतिशील रूप से डीकंप्रेस करने के लिए तर्क का अभाव होता है।"}},
{type:"mcq",diff:"hard",en:{q:"During a UEFI boot process, what dictates the exact path to the .efi bootloader that the firmware should execute?",opts:["The active flag in the MBR partition table","Boot variables stored within the motherboard's NVRAM","The BIOS Parameter Block inside the ESP","The bcdedit database exclusively"],ans:1,exp:"Unlike BIOS which blindly executes the first 512 bytes of a disk, UEFI firmware reads specific UEFI Boot Variables persistently stored inside the motherboard's NVRAM (Non-Volatile RAM). These variables contain the precise logical path to the intended bootloader (e.g., \\EFI\\Microsoft\\Boot\\bootmgfw.efi) located on the ESP."},hi:{q:"UEFI बूट प्रक्रिया के दौरान, वह क्या है जो .efi बूटलोडर का सटीक पथ (path) निर्धारित करता है जिसे फर्मवेयर को निष्पादित करना चाहिए?",opts:["MBR पार्टीशन टेबल में सक्रिय (Active) फ्लैग","मदरबोर्ड के NVRAM के भीतर संग्रहीत बूट चर (Boot variables)","ESP के अंदर BIOS पैरामीटर ब्लॉक","विशेष रूप से bcdedit डेटाबेस"],ans:1,exp:"BIOS के विपरीत जो आँख बंद करके डिस्क के पहले 512 बाइट्स को निष्पादित करता है, UEFI फर्मवेयर मदरबोर्ड के NVRAM (नॉन-वोलेटाइल RAM) के अंदर लगातार संग्रहीत विशिष्ट UEFI बूट वेरिएबल्स को पढ़ता है। इन चरों में ESP पर स्थित इच्छित बूटलोडर का सटीक तार्किक पथ होता है।"}},
{type:"tf",diff:"hard",en:{q:"The MBR is entirely OS-dependent; a Windows MBR cannot be overwritten by a Linux bootloader.",opts:["True","False"],ans:1,exp:"False. The Master Boot Record (MBR) is fundamentally OS-agnostic and consists of raw x86 machine code. A Linux bootloader like GRUB routinely overwrites the default Windows MBR code to take initial control and provide a multi-OS selection menu."},hi:{q:"MBR पूरी तरह से OS-निर्भर है; एक विंडोज MBR को लिनक्स बूटलोडर द्वारा ओवरराइट (overwritten) नहीं किया जा सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। मास्टर बूट रिकॉर्ड (MBR) मौलिक रूप से OS-अज्ञेयवादी (OS-agnostic) है और इसमें कच्चा x86 मशीन कोड होता है। लिनक्स बूटलोडर जैसे GRUB नियमित रूप से प्रारंभिक नियंत्रण लेने और मल्टी-ओएस चयन मेनू प्रदान करने के लिए डिफ़ॉल्ट विंडोज MBR कोड को अधिलेखित (overwrite) करते हैं।"}},
{type:"tf",diff:"hard",en:{q:"When performing a 'Warm Boot' via Ctrl+Alt+Del, the BIOS entirely bypasses the memory test portion of the POST phase.",opts:["True","False"],ans:0,exp:"True. During a Warm Boot (soft reset), a specific flag is set in the BIOS memory space (address 0040:0072h is set to 1234h). Upon detecting this flag, the BIOS explicitly skips the lengthy RAM counting/testing and most deep hardware initialization, significantly accelerating the boot process."},hi:{q:"Ctrl+Alt+Del के माध्यम से 'वार्म बूट' करते समय, BIOS पूरी तरह से POST चरण के मेमोरी परीक्षण (memory test) भाग को छोड़ देता है।",opts:["सही","गलत"],ans:0,exp:"सही। वार्म बूट (सॉफ्ट रीसेट) के दौरान, BIOS मेमोरी स्पेस में एक विशिष्ट फ्लैग सेट किया जाता है (पता 0040:0072h 1234h पर सेट है)। इस ध्वज का पता लगाने पर, BIOS स्पष्ट रूप से लंबी RAM गिनती/परीक्षण और अधिकांश गहन हार्डवेयर आरंभीकरण को छोड़ देता है, जिससे बूट प्रक्रिया काफी तेज हो जाती है।"}}
];
